INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('28-referral-os',3,28,'REFERRAL OS','He dieu hanh gioi thieu khach hang',28,'draft','2026-06-20T16:26:23Z','2026-06-20T16:26:23Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('09ef1519-5583-4207-bf65-8ce3933d9742','28-referral-os',NULL,2,'28.1 Vai Trò Của Referral OS Trong Hệ Sinh Thái Dental Empire','281-vai-tro-cua-referral-os-trong-he-sinh-thai-dental-empire',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f80f946e-6753-4af2-b647-c8759eeb9bf8','09ef1519-5583-4207-bf65-8ce3933d9742',0,'text','Khép lại **Chương 27: Patient OS**, chúng ta đã cùng nhau xây dựng và công nghiệp hóa toàn bộ hạ tầng trải nghiệm thực địa tại hòng khám. Từ những tin nhắn đếm ngược chặng Pre-Visit, tiêu chuẩn vận hành không ma sát đầu ghế In-Clinic, cho đến hệ thống đo lường toán học qua các chỉ số KPI vận hành và trải nghiệm. Mục tiêu tối cao của Patient OS là bịt kín mọi lỗ rò rỉ dữ liệu, triệt tiêu phản hồi tiêu cực và đưa mức độ hài lòng của người bệnh đạt đến trạng thái lý tưởng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('59ab12df-64a4-4b7c-b2fa-82432e91d6ea','09ef1519-5583-4207-bf65-8ce3933d9742',1,'text','Tuy nhiên, nếu chỉ dừng lại ở việc làm cho bệnh nhân hài lòng rồi tiễn họ ra cửa, phòng khám mới chỉ hoàn thành một nửa chu kỳ kinh doanh. Bạn đang lãng phí một nguồn tài nguyên vô hình nhưng có sức mạnh khủng khiếp: **Sự biết ơn và lòng tin tuyệt đối của người bệnh.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c6510d2d-8b47-41ce-a5cf-6aae0110ca25','09ef1519-5583-4207-bf65-8ce3933d9742',2,'text','*"Bạn không thể nhân bản một thứ không tồn tại. Nếu Patient OS là quá trình tối ưu hóa chất lượng gốc để đưa chỉ số hài lòng về mức tối đa, thì Referral OS chính là hệ số nhân giúp khuếch đại sự hài lòng đó thành các làn sóng khách hàng mới."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0e832a5b-62d5-444a-abb1-03659868d36e','09ef1519-5583-4207-bf65-8ce3933d9742',3,'text','Nếu không có một Patient OS vững chắc, mọi nỗ lực chạy chiến dịch giới thiệu sẽ thất bại, bởi vì không ai dại gì đem uy tín cá nhân của mình đi giới thiệu một phòng khám có dịch vụ tồi. Nhưng khi bộ máy Patient OS đã chạy trơn tru, phòng khám sẽ tự động tạo ra một lượng "thặng dư lòng tin" hằng ngày.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('70a854c5-0d79-4666-bfad-a25d1af47862','09ef1519-5583-4207-bf65-8ce3933d9742',4,'text','Để chuyển hóa lượng thặng dư này thành dòng doanh thu hữu cơ, giảm tải áp lực chi phí quảng cáo Paid Ads và biến mỗi bệnh nhân cũ thành một đại sứ thương hiệu hoạt động liên tục tại Hà Nội, chúng ta bắt buộc phải kích hoạt một hệ điều hành cao cấp hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('af66f67b-80fb-4d12-9966-24ae5dab854d','09ef1519-5583-4207-bf65-8ce3933d9742',5,'text','Chào mừng anh đến với **Chương 28: Referral OS - Hệ thống kích hoạt và quản trị nguồn khách giới thiệu tự nhiên**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e38effa8-0b56-40b5-9451-be95acc2deee','28-referral-os','09ef1519-5583-4207-bf65-8ce3933d9742',3,'Tư Duy Cốt Lõi: Công Nghiệp Hóa Lời Giới Thiệu','tu-duy-cot-loi-cong-nghiep-hoa-loi-gioi-thieu',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2f9c6cc1-405b-477a-ac7e-5a267f51c718','e38effa8-0b56-40b5-9451-be95acc2deee',6,'text','Trong hệ điều hành Dental Empire, lời giới thiệu (Referral) không phải là một hành vi may rủi, phụ thuộc hoàn toàn vào sự tự nguyện hay ngẫu hứng của bệnh nhân. Chúng tôi không vận hành phòng khám bằng cách "hy vọng" khách hàng sẽ nhớ đến mình khi người quen của họ đau răng. Lòng tin và sự giới thiệu của bệnh nhân phải được nhìn nhận như một loại tài nguyên tăng trưởng, cần được khai thác bằng một hệ thống kỹ thuật có quy trình, điểm chạm, kịch bản, KPI và công cụ theo dõi rõ ràng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e37caf72-7d61-4858-a89b-b3402d9ec1fe','e38effa8-0b56-40b5-9451-be95acc2deee',7,'text','Hệ điều hành **Referral OS** dịch chuyển phòng khám từ trạng thái "nhờ vả" bị động sang trạng thái "kích hoạt" chủ động. Bằng cách bẻ gãy hành trình tâm lý của người bệnh, chúng tôi lập trình sẵn các thời điểm vàng để đưa ra lời mời, thiết lập cơ chế tri ân tinh tế để biến một bệnh nhân hài lòng trở thành một đại sứ thương hiệu hoạt động liên tục tại thị trường Hà Nội.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e8a8de83-ba0c-41de-b0af-1291ecf7c8a4','28-referral-os','09ef1519-5583-4207-bf65-8ce3933d9742',3,'Ma Trận Dịch Chuyển Tư Duy Giới Thiệu Khách Hàng','ma-tran-dich-chuyen-tu-duy-gioi-thieu-khach-hang',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('227ed84d-5272-4c89-93f0-b534a94f6e9a','e8a8de83-ba0c-41de-b0af-1291ecf7c8a4',8,'image',NULL,'book/28-referral-os/8f660748-91b5-4876-a700-df6d3e10f482-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5766e163-fe4f-41b6-9044-53c56dbf2d15','28-referral-os','09ef1519-5583-4207-bf65-8ce3933d9742',3,'Năm Mục Tiêu Tăng Trưởng Chiến Lược Của Referral OS','nam-muc-tieu-tang-truong-chien-luoc-cua-referral-os',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4903dd5c-6eeb-47d3-802b-b8416fa37f86','5766e163-fe4f-41b6-9044-53c56dbf2d15',9,'text','Hệ thống được thiết kế để giải quyết dứt điểm bài toán chi phí marketing và nâng cao chất lượng nguồn khách đến sàn thực địa thông qua 5 đòn bẩy:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('522bd8b3-4955-4d00-b621-8de9d2efb6f1','5766e163-fe4f-41b6-9044-53c56dbf2d15',10,'text','**3.1 Tăng lượng bệnh nhân mới từ mỏ neo lòng tin có sẵn (Trust Anchor)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('191cdb91-9feb-49e9-af1c-f3755cf51c4a','5766e163-fe4f-41b6-9044-53c56dbf2d15',11,'text','Khách hàng mới được giới thiệu sẽ bỏ qua hoàn toàn giai đoạn nghi ngờ đầu phễu. Lòng tin của họ đối với người giới thiệu (bạn bè, người thân) được chuyển di thẳng sang cho năng lực chuyên môn của Bác sĩ, giúp rút ngắn thời gian tư vấn phác đồ tại sảnh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('38fd6aad-5872-40e4-9dae-f3a67afa2910','5766e163-fe4f-41b6-9044-53c56dbf2d15',12,'text','**3.2 Tối ưu hóa chi phí thu hút khách hàng (****CAC \\rightarrow 0****)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fa23b91f-cdce-4c5f-9c63-6527ea59fd2e','5766e163-fe4f-41b6-9044-53c56dbf2d15',13,'text','Khi nguồn khách mới đến từ luồng Referral tăng lên, phòng khám sẽ giảm dần sự phụ thuộc vào các chiến dịch quảng cáo trả phí đắt đỏ (Paid Ads). Đây là yếu tố cốt lõi để giữ vững biên lợi nhuận ròng của doanh nghiệp trong các giai đoạn thị trường cạnh tranh khốc liệt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('acb90282-1714-433c-aa70-544d7f8009ee','5766e163-fe4f-41b6-9044-53c56dbf2d15',14,'text','**3.3 Tăng tỷ lệ chuyển đổi nhờ chất lượng Lead vượt trội**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('12a36f34-b846-4390-b2be-d4add5cc499d','5766e163-fe4f-41b6-9044-53c56dbf2d15',15,'text','Hồ sơ bệnh nhân đến từ nguồn Referral có tỷ lệ đồng ý phác đồ điều trị (% Case Acceptance) cao hơn gấp 2.5 lần so với khách hàng biết đến phòng khám qua quảng cáo online, do họ đã được giáo dục trước về chất lượng dịch vụ và mức chi phí từ người giới thiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ab46c32d-71bd-42cb-9e5b-0fee1f93db8c','5766e163-fe4f-41b6-9044-53c56dbf2d15',16,'text','**3.4 Kéo giãn giá trị vòng đời bệnh nhân (****LTV****)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('375eda6e-d5e2-49a0-8726-1275db0e69ff','5766e163-fe4f-41b6-9044-53c56dbf2d15',17,'text','Hệ thống Referral tạo ra một sợi dây liên kết vô hình. Khi một bệnh nhân giới thiệu người thân đến khám, chính bản thân họ cũng sẽ có xu hướng gắn bó lâu dài hơn, có trách nhiệm bảo vệ kết quả điều trị của mình hơn để làm gương, từ đó tối ưu hóa chỉ số LTV.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('70b5c4ec-a3fa-4b0f-8da0-aa7b11f735c1','5766e163-fe4f-41b6-9044-53c56dbf2d15',18,'text','**3.4 Kích nổ hiệu ứng mạng lưới (Network Effect) trong 4 tầng lõi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5501a64a-893b-4809-a3d2-878bd8b645a7','5766e163-fe4f-41b6-9044-53c56dbf2d15',19,'text','Referral OS không chỉ dừng lại ở cá nhân. Hệ thống thiết lập các kịch bản riêng biệt để tạo vết dầu loang, chiếm lĩnh thị phần theo cụm:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e6492ce8-dc41-436f-97e0-61db2c9f7e78','5766e163-fe4f-41b6-9044-53c56dbf2d15',20,'text','- **Tầng gia đình:** Chăm sóc răng cho cả tổ ấm (bố mẹ, con cái).- **Tầng bạn bè:** Lan tỏa qua các nhóm tri kỷ, hội nhóm sở thích.- **Tầng cộng đồng:** Chiếm trọn lòng tin của các khu dân cư, cộng đồng theo dõi kênh.- **Tầng doanh nghiệp:** Ký kết các gói chăm sóc răng miệng đặc quyền cho nhân sự của các đối tác chiến lược.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dd37a95e-707a-4479-8462-1398916a5731','5766e163-fe4f-41b6-9044-53c56dbf2d15',21,'text','**Mantra điều hành Referral OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('65730d32-1a1c-4c7b-8c24-0c1dba4601b4','5766e163-fe4f-41b6-9044-53c56dbf2d15',22,'text','*"Đừng nhìn một bệnh nhân bước vào phòng khám như một cá thể đơn lẻ. Hãy nhìn họ như một cửa ngõ dẫn đến toàn bộ vòng tròn mối quan hệ của họ bao gồm gia đình, bạn bè và đồng nghiệp. Khai mở được cửa ngõ đó bằng sự tử tế và quy trình chuẩn xác chính là bí mật của sự tăng trưởng không giới hạn."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d96cef6a-5a9f-466c-a6b4-314adae5317d','28-referral-os',NULL,2,'28.2. Tư Duy Cốt Lõi Của Hệ Điều Hành Referral OS','282-tu-duy-cot-loi-cua-he-ieu-hanh-referral-os',4,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('91496222-273d-498d-8823-71e778b2b0a5','28-referral-os','d96cef6a-5a9f-466c-a6b4-314adae5317d',3,'Nền Tảng Gốc: Lời Giới Thiệu Là Hệ Quả, Không Phải Là Hành Vi Đi Xin','nen-tang-goc-loi-gioi-thieu-la-he-qua-khong-phai-la-hanh-vi-i-xin',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('da7a6953-549a-4d99-af44-431418d737ef','91496222-273d-498d-8823-71e778b2b0a5',23,'text','Một sai lầm chí mạng trong vận hành nha khoa là nhân sự vừa hoàn tất gắn răng sứ hay tháo niềng cho khách đã vội vã đưa thẻ giảm giá và ép họ đi giới thiệu người quen. **Referral không bắt đầu từ lời mời giới thiệu. Referral bắt đầu từ một trải nghiệm đủ vượt trội để bệnh nhân cảm thấy thôi thúc phải kể lại câu chuyện đó cho người khác.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5210e492-61c0-44de-a5b9-b0bde681ee1c','91496222-273d-498d-8823-71e778b2b0a5',24,'text','Trong hệ thống quản trị của **Thích Làm Răng**, chúng tôi không xem lời giới thiệu là một hành động ban ơn từ khách hàng. Đó là kết quả tất yếu của một phương trình vận hành chuẩn xác. Khi phòng khám giải quyết triệt để nỗi sợ đau, minh bạch hóa chi phí và tạo ra một kết quả lâm sàng mỹ mãn, bệnh nhân sẽ tự động phát sinh nhu cầu chia sẻ như một cách để khẳng định quyết định tiêu dùng thông minh của bản thân họ trước bạn bè và gia đình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2c88660c-9834-4db9-8116-76ddaf7b0857','28-referral-os','d96cef6a-5a9f-466c-a6b4-314adae5317d',3,'Mô Hình Toán Học: Công Thức Tăng Trưởng Referral Trong Dental Empire','mo-hinh-toan-hoc-cong-thuc-tang-truong-referral-trong-dental-empire',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bf471378-ece8-4690-b831-1cc5639348f7','2c88660c-9834-4db9-8116-76ddaf7b0857',25,'image',NULL,'book/28-referral-os/f1239591-200b-4c09-b9e5-c12ce6f09f09-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('068eec37-bd76-42df-a13d-ab7b892b9365','28-referral-os','d96cef6a-5a9f-466c-a6b4-314adae5317d',3,'Bóc Tách Các Biến Số Trong Phương Trình Tăng Trưởng','boc-tach-cac-bien-so-trong-phuong-trinh-tang-truong',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('16ad40aa-0c72-444e-be71-1a702c08abb5','068eec37-bd76-42df-a13d-ab7b892b9365',26,'text','Hệ thống bẻ gãy 4 biến số đầu vào của phương trình thành các tiêu chuẩn hành vi cứng trên CRM:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9231e813-a11e-4a9c-8389-e8dec34039b4','068eec37-bd76-42df-a13d-ab7b892b9365',27,'text','**Good Result (Kết quả lâm sàng xuất sắc)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f72e8b34-fa3e-458e-b94c-1daa5760f1a7','068eec37-bd76-42df-a13d-ab7b892b9365',28,'text','- **Bản chất:** Là điều kiện cần và là móng nền y khoa bắt buộc.- **Biểu hiện thực tế:** Bệnh nhân ăn nhai ngon miệng, không ê buốt, dáng răng sứ tự nhiên hoặc trục răng chỉnh nha chuẩn tỷ lệ vàng. Khách hàng tự cảm nhận rõ rệt sự thay đổi diện mạo và nâng cấp sức khỏe sinh học của bản thân khi soi gương hằng ngày.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6a49ef36-b854-4f22-8b67-934abf1f85f8','068eec37-bd76-42df-a13d-ab7b892b9365',29,'text','**Good Experience (Trải nghiệm điểm chạm trọn vẹn)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ae4082b5-0852-4c00-a97c-e0e95d173ab9','068eec37-bd76-42df-a13d-ab7b892b9365',30,'text','- **Bản chất:** Là điều kiện đủ để gỡ bỏ hoàn toàn ma sát tâm lý trong suốt hành trình khách hàng.- **Biểu hiện thực tế:** Sự hài lòng đồng bộ từ cách Lễ tân chào đón đúng tên riêng, thời gian chờ đợi dưới 10 phút, Bác sĩ tư vấn phác đồ dễ hiểu trực quan trên phim chụp, cho đến quy trình kiểm soát đau bốn tay chuyên nghiệp tại phòng VIP.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e95b877a-8b75-4d7a-a4a2-ac8a628b8050','068eec37-bd76-42df-a13d-ab7b892b9365',31,'text','**Good Relationship (Mối quan hệ gắn kết)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8f9e9a25-8d42-4203-bf17-5948be8d7a7b','068eec37-bd76-42df-a13d-ab7b892b9365',32,'text','- **Bản chất:** Duy trì mỏ neo kết nối cảm xúc, triệt tiêu tư duy "săn bắn/chốt tiền xong là biến mất" của các phòng khám nghiệp dư.- **Biểu hiện thực tế:** Hệ thống tự động kích nổ các tin nhắn hỏi thăm sức khỏe đúng các mốc giờ vàng sau điều trị (2h - 24h - 3 ngày), gửi bài viết chia sẻ kiến thức chăm sóc răng miệng cá nhân hóa, và chúc mừng sinh nhật kèm quà tặng thiết thực.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('05d53858-a0ce-43d6-a5d8-7ea270184901','068eec37-bd76-42df-a13d-ab7b892b9365',33,'text','**Easy Sharing Mechanism (Cơ chế chia sẻ không ma sát)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('40208767-897d-43f4-9bda-eb2b9a6cbefa','068eec37-bd76-42df-a13d-ab7b892b9365',34,'text','- **Bản chất:** Cung cấp công cụ và lý do tinh tế để khách hàng thực hiện hành vi giới thiệu mà không có cảm giác bị ngượng hay mang tính thương mại hóa.- **Biểu hiện thực tế:** Phòng khám thiết kế sẵn các công cụ vật lý và kỹ thuật số tinh gọn: Thẻ Đặc Quyền Nụ Cười (mã định danh ID trên CRM), mã QR giới thiệu cá nhân hóa, hoặc tin nhắn mẫu dễ dàng chuyển tiếp (Forward) qua Zalo cho người thân chỉ bằng một cú chạm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b0c0d461-4dbf-4f7d-b12c-be171a7cd58a','068eec37-bd76-42df-a13d-ab7b892b9365',35,'text','**Mantra điều hành Tư duy Referral:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8980bebf-abf1-4b66-a5ed-45a7dd3a91f0','068eec37-bd76-42df-a13d-ab7b892b9365',36,'text','*"Nếu kết quả điều trị tệ, mọi kịch bản giới thiệu đều là vô nghĩa. Nếu trải nghiệm tồi, không một phần quà nào có thể mua được uy tín cá nhân của bệnh nhân. Hãy làm tốt 3 biến số đầu tiên để tích lũy thặng dư lòng tin, và dùng biến số thứ 4 để khơi thông dòng chảy doanh thu hữu cơ đó."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('75efce53-b440-414f-ad74-b45e606fab47','28-referral-os',NULL,2,'28.3 Vị trí của Referral OS trong Customer Journey','283-vi-tri-cua-referral-os-trong-customer-journey',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7dfe62c9-f3b4-4023-a926-d40e85bcf973','75efce53-b440-414f-ad74-b45e606fab47',37,'text','Referral OS nằm sau giai đoạn Patient Experience, nhưng thực tế phải được chuẩn bị từ rất sớm trong hành trình khách hàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('69aec0d1-2df9-450f-be06-3b8bf680cbcb','75efce53-b440-414f-ad74-b45e606fab47',38,'image',NULL,'book/28-referral-os/8c50a6a7-defb-48a9-8e66-71d7c9b2bab9-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7d30daf8-e39f-4c9a-88ca-680689e913c1','75efce53-b440-414f-ad74-b45e606fab47',39,'text','Referral không nên được xem là một bước cuối cùng tách rời. Nó là kết quả của toàn bộ hệ thống phía trước.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5cf9b69e-8991-420b-a23c-9e8b571153ec','75efce53-b440-414f-ad74-b45e606fab47',40,'text','Nếu marketing tạo kỳ vọng sai, sales tư vấn quá đà, clinic vận hành kém, patient care không theo sát, thì Referral OS sẽ yếu dù có chương trình thưởng tốt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6266570b-8f99-469b-bc22-e04883c67375','28-referral-os',NULL,2,'28.4 Năm Mục Tiêu Chiến Lược Và Bánh Đà Tăng Trưởng Tích Lũy','284-nam-muc-tieu-chien-luoc-va-banh-a-tang-truong-tich-luy',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aff92e1f-e5a5-433a-9446-855f85eb55d7','6266570b-8f99-469b-bc22-e04883c67375',41,'text','Hệ thống **Referral OS** được vận hành không phải để thu về vài lời giới thiệu nhỏ lẻ. Đây là trục động cơ tăng trưởng hữu cơ, được thiết kế để hoàn chỉnh mảnh ghép cuối cùng trong hành trình khách hàng, hướng tới 5 mục tiêu tối cao dưới đây.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6ab78ead-30c0-4ce1-9716-d0cf46ceded9','28-referral-os','6266570b-8f99-469b-bc22-e04883c67375',3,'Bóc Tách Năm Mục Tiêu Vận Hành Chiến Lược','boc-tach-nam-muc-tieu-van-hanh-chien-luoc',10,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a6aeb585-8a88-4ee7-9fa0-5d9d89afd9a4','6ab78ead-30c0-4ce1-9716-d0cf46ceded9',42,'text','**4.1 Chuyển hóa sự hài lòng thụ động thành hành vi chủ động**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('634a966d-795f-4083-8772-e96a5022a735','6ab78ead-30c0-4ce1-9716-d0cf46ceded9',43,'text','Sự hài lòng mặc định của bệnh nhân là một nguồn năng lượng tĩnh. Nếu phòng khám không chủ động tạo ra các điểm chạm kích hoạt (Trigger Points) tinh tế tại sảnh Hà Nội, khách hàng sẽ ra về trong im lặng. Referral OS sinh ra để tạo ra cái cớ hợp lý, biến những lời khen ngợi tại quầy thành hành động chia sẻ thực tế.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e554c618-2a35-43d1-a9cd-2cb96c65ec1e','6ab78ead-30c0-4ce1-9716-d0cf46ceded9',44,'text','**4.2 Khai thác nguồn bệnh nhân mới có độ tin cậy tuyệt đối**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f7c3cbaf-358d-4ee4-a4e2-a921539bd25f','6ab78ead-30c0-4ce1-9716-d0cf46ceded9',45,'text','Khác với khách hàng đến từ quảng cáo trực tuyến (Paid Ads) luôn mang tâm lý đề phòng, nhóm khách hàng Referral bước vào nha khoa với một mỏ neo lòng tin đã được cắm sẵn. Họ tin vào lời bảo chứng của người thân, giúp giảm tối đa thời gian đấu trí về giá và rút ngắn chu kỳ chốt phác đồ điều trị lớn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('72cb3aa5-e543-4aca-a426-411d0396d63e','6ab78ead-30c0-4ce1-9716-d0cf46ceded9',46,'text','**4.3 Tối ưu hóa hiệu suất khai thác doanh thu trên mỗi hồ sơ khách hàng**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7ebe691c-8966-4e0a-bbd3-a304b7454ea0','6ab78ead-30c0-4ce1-9716-d0cf46ceded9',47,'text','Doanh thu của một bệnh nhân không chỉ dừng lại ở số tiền họ chi trả trên hóa đơn cá nhân. Một bệnh nhân trung thành được hệ thống kích hoạt tốt sẽ trở thành một "trung tâm phân phối lòng tin", kéo theo cả gia đình, nhóm bạn thân hoặc đồng nghiệp cùng cơ quan sử dụng dịch vụ, tạo ra dòng doanh thu gián tiếp khổng lồ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('22359f1d-9d17-47ae-af0c-249d28454d5f','6ab78ead-30c0-4ce1-9716-d0cf46ceded9',48,'text','**4.4 Xây dựng bộ tộc hộ vệ thương hiệu (Brand Advocates)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d0ef19de-cbb3-4c2e-bdf9-fc8d4549bc38','6ab78ead-30c0-4ce1-9716-d0cf46ceded9',49,'text','Vượt lên trên câu chuyện tài chính, hệ thống hướng tới việc xây dựng một cộng đồng những người sẵn sàng lên tiếng bảo vệ uy tín của Bác sĩ Vinh và thương hiệu trên không gian mạng. Đây là hạ tầng an ninh thương hiệu vững chắc nhất giúp phòng khám miễn nhiễm trước các cuộc khủng hoảng truyền thông ác ý.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7ec52c25-6d1a-45c3-8b12-41c32be7746e','6ab78ead-30c0-4ce1-9716-d0cf46ceded9',50,'text','**4.5 Kích nổ bánh đà tăng trưởng tích lũy tự thân (The Referral Flywheel)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fda45396-3e34-457c-a3f1-c2dfa76c77be','6ab78ead-30c0-4ce1-9716-d0cf46ceded9',51,'text','Referral OS chuyển dịch phòng khám từ thế tăng trưởng tuyến tính (phụ thuộc vào việc nạp tiền quảng cáo) sang thế tăng trưởng hàm số mũ (tự tích lũy động năng). Mỗi bệnh nhân mới được giới thiệu thành công lại trở thành một điểm khởi đầu mới cho một chu kỳ lòng tin tiếp theo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9eab45a9-68d1-488f-a124-97c9fc5e3da7','28-referral-os','6266570b-8f99-469b-bc22-e04883c67375',3,'Cơ Chế Vận Hành Của Bánh Đà Tăng Trưởng Dental Empire','co-che-van-hanh-cua-banh-a-tang-truong-dental-empire',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fb4360d1-f907-4039-88db-6de92fef28d1','9eab45a9-68d1-488f-a124-97c9fc5e3da7',52,'text','Hệ thống quản trị thiết lập và giám sát chu kỳ tăng trưởng khép kín thông qua mô hình chuyển dịch năng lượng 7 chặng dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d498b379-7107-4de5-92e3-2d97ac71178e','9eab45a9-68d1-488f-a124-97c9fc5e3da7',53,'image',NULL,'book/28-referral-os/9af01852-c006-473d-b4d1-b9f23d897314-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('29731330-5a33-4406-8459-837fd6b668a0','28-referral-os','6266570b-8f99-469b-bc22-e04883c67375',3,'Ma Trận Đối Soát Chỉ Số Mục Tiêu Theo Tầng Dữ Liệu','ma-tran-oi-soat-chi-so-muc-tieu-theo-tang-du-lieu',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fe586c56-1cea-4f74-abe0-562ef6a5959d','29731330-5a33-4406-8459-837fd6b668a0',54,'text','Ban quản trị phòng khám đo lường mức độ hoàn thành 5 mục tiêu trên thông qua bảng định lượng dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0a37a24f-9085-4929-97d2-81c11e3fe30c','29731330-5a33-4406-8459-837fd6b668a0',55,'image',NULL,'book/28-referral-os/6a34e47f-f03f-4e99-bd7e-abe2aa6dc9d4-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f982a1fa-1249-45e2-b977-8fe1fd0dcb25','29731330-5a33-4406-8459-837fd6b668a0',56,'text','**Mantra điều hành mục tiêu:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d299ce92-54a4-478d-a619-1182f4cf45e3','29731330-5a33-4406-8459-837fd6b668a0',57,'text','*"Mục tiêu cuối cùng của Referral OS không phải là cố gắng bán thêm một dịch vụ, mà là xây dựng một mạng lưới người ủng hộ tự vận hành. Khi bánh đà tăng trưởng này đạt đủ số vòng quay, phòng khám sẽ bước vào trạng thái tự sinh trưởng mà không cần đốt thêm ngân sách cho các chiến dịch marketing ngắn hạn."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9acd0c98-9a18-4457-85ec-23fcf0ccf651','28-referral-os',NULL,2,'28.5 Bản Đồ Kiến Trúc 7 Lớp Của Hệ Điều Hành Referral OS','285-ban-o-kien-truc-7-lop-cua-he-ieu-hanh-referral-os',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8946f48b-5b45-4edb-8a42-9a1e18a426a7','9acd0c98-9a18-4457-85ec-23fcf0ccf651',58,'text','Để hệ thống tăng trưởng bằng lời giới thiệu vận hành tự động và chính xác,hạ tầng **Referral OS** được kiến trúc theo mô hình kiến trúc 7 lớp chuyên biệt. Mỗi lớp đóng vai trò là một mắt xích không thể tách rời, chuyển hóa dòng chảy dữ liệu từ một ca điều trị thành công thành các làn sóng khách hàng mới.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('459e7f34-bb2c-4e62-9943-f09c031b7437','28-referral-os','9acd0c98-9a18-4457-85ec-23fcf0ccf651',3,'Sơ Đồ Tổng Quan Kiến Trúc 7 Lớp (Referral Architecture Stack)','so-o-tong-quan-kien-truc-7-lop-referral-architecture-stack',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0c50db59-6821-4357-8315-a600f2b966d0','459e7f34-bb2c-4e62-9943-f09c031b7437',59,'image',NULL,'book/28-referral-os/61938f8f-2355-4322-a77c-d6eb25d08263-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1289b908-1492-4794-90b6-45e67b2ff234','28-referral-os','9acd0c98-9a18-4457-85ec-23fcf0ccf651',3,'Bóc Tách Chi Tiết Vận Hành Của 7 Lớp Cốt Lõi','boc-tach-chi-tiet-van-hanh-cua-7-lop-cot-loi',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('91ef9bd9-49cd-4056-b3c8-70a0d28faa99','1289b908-1492-4794-90b6-45e67b2ff234',60,'text','**1. Lớp 1: Referral Foundation (Nền tảng hệ thống)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a72ffe29-7166-4e13-8718-dfe1103ab3af','1289b908-1492-4794-90b6-45e67b2ff234',61,'text','- **Chức năng:** Xây dựng phần móng vững chắc nhất về mặt chuyên môn lâm sàng và trải nghiệm dịch vụ.- **Tiêu chuẩn vận hành:** Lớp này thực thi nghiêm ngặt phương trình gốc: \\text{Good Result} + \\text{Good Experience} + \\text{Good Relationship}. Nếu bác sĩ điều trị lỗi hoặc sảnh chờ gây ức chế cho khách, lớp nền tảng sẽ sụp đổ, phòng khám lập tức khóa tính năng xin giới thiệu để bảo vệ thương hiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1e11adc4-ca95-4c34-830a-3c34f55e73fa','1289b908-1492-4794-90b6-45e67b2ff234',62,'text','**2. Lớp 2: Referral Trigger (Điểm chạm kích hoạt)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a837c3f5-2867-44cb-9ede-faf297d3ee2d','1289b908-1492-4794-90b6-45e67b2ff234',63,'text','- **Chức năng:** Lập trình các "bẫy thời gian" trên CRM để nhắc nhở nhân sự đưa ra lời mời đúng lúc.- **Tiêu chuẩn vận hành:** Triệt tiêu hoàn toàn việc hỏi xin ngẫu nhiên. Điểm kích hoạt chỉ được bật lên vào 6 thời điểm vàng: ngay khi khách chủ động khen ngợi bác sĩ, khi tháo niềng/lắp răng sứ thành công, sau khi khách để lại review 5 sao, hoặc khi khách chủ động hỏi giải pháp cho người thân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6e6e6373-4fb5-4d53-9192-0caf18286aea','1289b908-1492-4794-90b6-45e67b2ff234',64,'text','**3. Lớp 3: Referral Offer (Cơ chế đặc quyền)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('093c3727-cecf-40ee-a209-90dceb6b1ba0','1289b908-1492-4794-90b6-45e67b2ff234',65,'text','- **Chức năng:** Thiết kế phần thưởng và lý do chia sẻ mang tính danh giá, tinh tế, loại bỏ yếu tố thương mại hóa thô bạo (không chi tiền mặt làm giảm uy tín ngành y).- **Tiêu chuẩn vận hành:** Sử dụng công cụ vật lý và kỹ thuật số cao cấp như **Thẻ Đặc Quyền Nụ Cười**. Cơ chế tri ân tập trung vào lợi ích thiết thực: Miễn phí khám/chụp phim 3D CT cho người được giới thiệu và cộng điểm nâng hạng thành viên VIP kèm quà tặng chăm sóc răng chuyên sâu cho người giới thiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('951071c2-cdb2-49d9-9cca-1bacbfb6e0c5','1289b908-1492-4794-90b6-45e67b2ff234',66,'text','**4. Lớp 4: Referral Script (Bộ kịch bản không ma sát)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b78358d2-b039-4e00-b174-80ccaa6216c8','1289b908-1492-4794-90b6-45e67b2ff234',67,'text','- **Chức năng:** Chuẩn hóa ngôn từ cho đội ngũ trực sàn và hệ thống nhắn tin tự động qua Zalo OA.- **Tiêu chuẩn vận hành:** Chia rõ thành hai luồng kịch bản: **Kịch bản mềm** (gợi mở chân thành khi khách hàng hạnh phúc sau điều trị) và **Kịch bản ưu đãi** (kèm theo thẻ đặc quyền hội viên khi hoàn tất ca lớn). Câu từ ngắn gọn, đi thẳng vào quyền lợi sức khỏe của người thân, không tạo áp lực tâm lý cho người nói lẫn người nghe.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3ef26112-8279-4f2d-8ccb-d3ddb6d22b26','1289b908-1492-4794-90b6-45e67b2ff234',68,'text','**5. Lớp 5: Referral Tracking (Hạ tầng số hóa truy vết)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f8bfc708-ab6b-479b-ba2d-6e4c47d6b170','1289b908-1492-4794-90b6-45e67b2ff234',69,'text','- **Chức năng:** Lập bản đồ và ghi nhận chính xác "cây phả hệ khách hàng" trên CRM, tuyệt đối không để xảy ra tình trạng mất dữ liệu công sức của người giới thiệu.- **Tiêu chuẩn vận hành:** Khi khách hàng mới đến sàn, hệ thống bắt buộc phải liên kết mã ID của họ vào ID của khách hàng cũ qua trường dữ liệu `Referrer_ID`. Hệ thống tự động phân loại nguồn và ghi nhận lịch sử đóng góp doanh thu gián tiếp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4c6fc227-65d1-448c-b975-2c36caad282b','1289b908-1492-4794-90b6-45e67b2ff234',70,'text','**6. Lớp 6: Referral Care (Chiến dịch chăm sóc kép)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fb39cbbb-b75a-4203-9cc9-40d70ee39b97','1289b908-1492-4794-90b6-45e67b2ff234',71,'text','- **Chức năng:** Vận hành quy trình chăm sóc đồng thời cả 2 đầu khách hàng (Người giới thiệu & Người được giới thiệu) để tối đa hóa điểm chạm cảm xúc.- **Tiêu chuẩn vận hành:***Đối với người được giới thiệu:* Tiếp đón theo tiêu chuẩn VIP, xếp lịch ghế nha ưu tiên, Bác sĩ Vinh trực tiếp kiểm tra.- *Đối với người giới thiệu:* Ngay khi người quen của họ đến khám thành công, hệ thống lập tức bắn tin nhắn cảm ơn cá nhân hóa và kích hoạt quà tặng tri ân vào tài khoản của họ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6a72b631-8e03-4f0c-a0a5-bd763f28e4e5','1289b908-1492-4794-90b6-45e67b2ff234',72,'text','**7. Lớp 7: Referral Flywheel (Tối ưu hóa vòng lặp)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0bb4f9eb-5335-4cec-b670-941ce7b0e570','1289b908-1492-4794-90b6-45e67b2ff234',73,'text','- **Chức năng:** Đo lường các chỉ số toán học (RTR, Doanh thu khách cũ, LTV) để kiểm toán hiệu suất, vá lỗ hổng vận hành và biến nhóm khách hàng mới được giới thiệu thành những người tiếp tục đi giới thiệu.- **Tiêu chuẩn vận hành:** Quản lý tổ chức rà soát dữ liệu định kỳ mỗi tháng một lần. Nếu bánh đà có dấu hiệu nghẽn (khách mới đến nhiều nhưng không phát sinh review hoặc không tiếp tục tặng thẻ cho người khác), bộ phận CSKH phải kiểm tra lại chất lượng điểm chạm lâm sàng ngay lập tức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cdf712b7-c964-4b60-a851-545bdb49f252','1289b908-1492-4794-90b6-45e67b2ff234',74,'text','**Mantra điều hành cấu trúc:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('60f3771c-268e-4406-8de6-0d6d63aea908','1289b908-1492-4794-90b6-45e67b2ff234',75,'text','*"Kiến trúc 7 lớp của Referral OS hoạt động như một dây chuyền sản xuất lòng tin. Một phòng khám không có cấu trúc rõ ràng sẽ khiến nhân sự lúng túng không biết khi nào nên nói, nói câu gì, và làm sao để ghi nhận cho khách. Hãy chạy đồng bộ cả 7 lớp để biến lời giới thiệu thành một nguồn tài sản tăng trưởng có thể kiểm soát và dự báo trước."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f362cbc9-458f-428a-ae25-d7525b2335ce','28-referral-os','9acd0c98-9a18-4457-85ec-23fcf0ccf651',3,'Chi tiết từ lớp','chi-tiet-tu-lop',16,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c09b045d-61af-4fdc-9aef-72bf83707517','28-referral-os','f362cbc9-458f-428a-ae25-d7525b2335ce',4,'LỚP 1: Referral Foundation - Nền Tảng Tạo Giới Thiệu','lop-1-referral-foundation-nen-tang-tao-gioi-thieu',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9d93fc62-cf64-4609-bf20-555f5850abfe','c09b045d-61af-4fdc-9aef-72bf83707517',76,'text','Lớp nền tảng (Foundation) là phần móng quan trọng nhất của toàn bộ hệ thống Referral OS. Nếu không xây dựng được một nền móng vững chắc về chất lượng lâm sàng và sự an tâm tuyệt đối của người bệnh, mọi chương trình tri ân hay quà tặng phía sau sẽ biến tướng thành hành vi ép khách, mồi chài thô bạo, gây phản cảm và phá hủy uy tín thương hiệu ngay lập tức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7ec9d361-595b-4420-b891-018cb5bbf84f','28-referral-os','c09b045d-61af-4fdc-9aef-72bf83707517',5,'Bốn Điều Kiện Tâm Lý Kích Hoạt Hành Vi Giới Thiệu','bon-ieu-kien-tam-ly-kich-hoat-hanh-vi-gioi-thieu',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4dae0e47-cff6-4508-bcc1-08de30ea5f37','7ec9d361-595b-4420-b891-018cb5bbf84f',77,'image',NULL,'book/28-referral-os/ea146801-c8e5-459b-b4ca-de5770092c22-img07.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('da816d59-1ead-405e-8f61-09f9a3aaab9f','7ec9d361-595b-4420-b891-018cb5bbf84f',78,'text','Trước khi mở lời chia sẻ, bộ não của bệnh nhân sẽ tự động thực hiện một bài kiểm toán nhanh thông qua 4 câu hỏi ngầm định:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a0e9181f-e39b-4f20-8a7d-6b69531df145','7ec9d361-595b-4420-b891-018cb5bbf84f',79,'text','- *“Phòng khám nha khoa này có thực sự đủ tử tế và đẳng cấp để mình đem danh dự cá nhân ra bảo chứng không?”*- *“Người thân hay bạn bè của mình khi đến đây có chắc chắn được Bác sĩ Vinh và ekip đối xử chu đáo, tôn trọng không?”*- *“Nếu chẳng may ca điều trị của người quen gặp trục trặc lâm sàng, mối quan hệ giữa mình và họ có bị ảnh hưởng hay rạn nứt không?”*- *“Có điểm chạm đặc biệt nào tại đây giúp mình cảm thấy tự hào và nâng cao vị thế cá nhân khi kể cho người khác nghe không?”*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('afc9760d-4954-4fd1-b558-07ebcacec4d0','7ec9d361-595b-4420-b891-018cb5bbf84f',80,'text','**Tử huyệt của Lớp Nền tảng:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cbe64da8-be3a-42f0-8e9f-52b186716113','7ec9d361-595b-4420-b891-018cb5bbf84f',81,'text','Bản chất của hành vi giới thiệu là việc khách hàng cho phòng khám "vay" uy tín cá nhân của họ. Vì vậy, nhiệm vụ tối cao của Referral OS là phải vận hành sao cho bảo vệ và gia tăng sự tôn nghiêm, uy tín của chính người giới thiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0117fc86-9eb1-4d99-b59a-dbf5bc658038','28-referral-os','c09b045d-61af-4fdc-9aef-72bf83707517',5,'Ma Trận Bảy Tiền Đề Bắt Buộc Trước Khi Kích Hoạt System','ma-tran-bay-tien-e-bat-buoc-truoc-khi-kich-hoat-system',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c74fd809-f718-43fe-bf90-f1bbf0451fbf','0117fc86-9eb1-4d99-b59a-dbf5bc658038',82,'text','Ban quản trị nha khoa nghiêm cấm việc triển khai các chiến dịch Referral đại trà khi chưa nghiệm thu và tích hợp đồng bộ 7 hạ tầng tiền đề bắt buộc dưới đây lên hệ thống:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8c489567-46ec-4f25-91be-52560cee0bd7','0117fc86-9eb1-4d99-b59a-dbf5bc658038',83,'image',NULL,'book/28-referral-os/7c71b79a-ccc1-4201-89b8-79ecdbffd86d-img08.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6a32de6e-a519-4a2c-95f5-a614e7c8eca2','0117fc86-9eb1-4d99-b59a-dbf5bc658038',84,'text','**Mantra điều hành Referral Foundation:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1e31a352-4230-41a4-9c1e-f0ca4590e13d','0117fc86-9eb1-4d99-b59a-dbf5bc658038',85,'text','*"Đừng cố gắng kích hoạt một hệ thống tăng trưởng bằng giới thiệu khi phòng khám vẫn còn để xảy ra lỗi lâm sàng hay làm khách hàng bực mình vì thời gian chờ đợi. Hãy tối ưu hóa chất lượng gốc của sản phẩm dịch vụ trước. Lời giới thiệu chỉ là phần thặng dư tự nhiên xuất hiện khi bạn phục vụ người bệnh vượt trên sự kỳ vọng của họ."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('da175779-6791-48de-8ed7-fc7cf91b2aef','28-referral-os','f362cbc9-458f-428a-ae25-d7525b2335ce',4,'LỚP 2: Referral Trigger - Điểm Kích Hoạt Giới Thiệu','lop-2-referral-trigger-iem-kich-hoat-gioi-thieu',20,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('43eebfd9-3623-4ded-9c96-9f86b8c0d378','28-referral-os','da175779-6791-48de-8ed7-fc7cf91b2aef',5,'Tư Duy Vận Hành: Đánh Bắt Cảm Xúc Tại Đỉnh Cao Trải Nghiệm (Peak-End Rule)','tu-duy-van-hanh-anh-bat-cam-xuc-tai-inh-cao-trai-nghiem-peak-end-rule',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d04dd59b-c525-4f84-8f9a-b617dc82dc52','43eebfd9-3623-4ded-9c96-9f86b8c0d378',86,'text','Một trong những nguyên nhân khiến tỷ lệ khách giới thiệu tại các phòng khám truyền thống rất thấp là do nhân sự đưa ra lời mời hoàn toàn sai thời điểm. Hỏi xin lời giới thiệu khi bệnh nhân vừa trải qua một ca nhổ răng khôn mệt mỏi, hoặc khi họ đang vội vã thanh toán để đi làm sẽ tạo ra sự phiền toái lớn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('81f3fb43-78c3-4a14-a8a8-9d1b761c47b1','43eebfd9-3623-4ded-9c96-9f86b8c0d378',87,'text','Hệ thống **Referral Trigger**  hoạt động dựa trên nguyên lý tâm lý học hành vi: *Con người chỉ sẵn sàng chia sẻ và lan tỏa khi mức độ hưng phấn cảm xúc hoặc lòng biết ơn của họ đạt đỉnh (**`Peak Wow`**)*. Đội ngũ nhân sự trực sàn tại Hà Nội và bộ phận CSKH trực tuyến cần được huấn luyện để nhạy bén nhận diện các "khoảnh khắc hài lòng", từ đó bật công tắc kích hoạt đường ống giới thiệu một cách tự nhiên và mượt mà nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3cf386ed-769f-4867-8d8b-608e47d1834c','28-referral-os','da175779-6791-48de-8ed7-fc7cf91b2aef',5,'Năm Thời Điểm Vàng Kích Nổ Luồng Giới Thiệu','nam-thoi-iem-vang-kich-no-luong-gioi-thieu',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1c75c9e7-ab7d-46df-a83b-5449de761603','3cf386ed-769f-4867-8d8b-608e47d1834c',88,'text','Hệ thống CRM thiết lập cơ chế giám sát và chỉ cho phép kích hoạt quy trình Referral vào đúng 5 cửa sổ thời gian vàng dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cf85f4a5-215f-4309-b371-87ee3bd03628','3cf386ed-769f-4867-8d8b-608e47d1834c',89,'text','**Ngay sau khi bệnh nhân nhìn thấy kết quả lâm sàng rõ ràng (Visual & Physical Proof)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d52469cb-5452-4ef1-a615-7871c6fe1ca0','3cf386ed-769f-4867-8d8b-608e47d1834c',90,'text','Đây là thời điểm mà các bằng chứng y khoa hiển thị trực quan nhất, giải tỏa mọi hoài nghi của bệnh nhân trước đó. Cảm xúc tích cực lúc này đạt mức tối đa:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('32b20566-8a66-445b-93d9-66799c51febe','3cf386ed-769f-4867-8d8b-608e47d1834c',91,'text','- **Ca Chỉnh nha:** Buổi tháo niềng hoàn tất, bệnh nhân nhìn thấy cung hàm đều đặn và sự thay đổi rõ rệt của góc nghiêng gương mặt.- **Ca Phục hình/Thẩm mỹ:** Gắn thành công mão sứ cố định, khớp cắn chuẩn xác, răng sứ sáng bóng tự nhiên.- **Ca Điều trị bệnh lý:** Vùng răng sâu, viêm tủy chính thức hết đau nhức, ăn nhai bình thường trở lại.- **Ca Tẩy trắng răng:** Kết quả lên tone rõ rệt ngay sau khi bước xuống ghế nha.- **Ca Implant:** Trạng thái tích hợp xương ổn định, lắp nhịp răng hoàn chỉnh sau nhiều tháng chờ đợi.- **Ca Nha khoa trẻ em:** Trẻ nhỏ hợp tác tốt với Bác sĩ Vinh, không khóc thét, hoàn thành buổi điều trị vui vẻ (kích hoạt trigger thẳng tới phụ huynh).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('66b21b7a-59db-45df-95a6-9b8a5c56a56c','3cf386ed-769f-4867-8d8b-608e47d1834c',92,'text','**Ngay sau khi bệnh nhân để lại đánh giá tích cực (The Micro-Commitment Escalation)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b30f96eb-716d-4b79-b036-a20cfd5ecda2','3cf386ed-769f-4867-8d8b-608e47d1834c',93,'text','Khi một bệnh nhân đã sẵn sàng dành thời gian viết một bài đánh giá tốt trên không gian mạng, họ đã tự thiết lập một cam kết ngầm về lòng trung thành với thương hiệu. Đây là bước đệm hoàn hảo để nâng cấp hành vi từ "Người để lại đánh giá" thành "Người đi giới thiệu". Quy trình leo thang điểm chạm được CRM tự động hóa theo tuyến tính:',NULL,NULL,NULL,NULL,NULL);
