INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a1101ab8-29ce-40db-ab3c-703fb84d59c0','3cf386ed-769f-4867-8d8b-608e47d1834c',95,'text','CSKH gửi tin nhắn hỏi thăm trạng thái ăn nhai sau điều trị qua Zalo OA.',NULL,NULL,NULL,NULL,NULL);
