INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a983c26b-4e79-45e2-90c6-b29bfd013f35','3cf386ed-769f-4867-8d8b-608e47d1834c',97,'text','Nếu khách phản hồi tích cực, hướng dẫn khách quét mã QR để lại Review 5 sao trên Google Maps.',NULL,NULL,NULL,NULL,NULL);
