INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5f4d0456-564c-4709-9e2a-6a91e6bfb68b','3cf386ed-769f-4867-8d8b-608e47d1834c',99,'text','Sau khi hệ thống ghi nhận Review thành công, lập tức gửi lời cảm ơn và lồng ghép kịch bản tặng thẻ đặc quyền tri ân người thân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a6762dae-a463-4c1e-ba8a-3e8bc7ce1fc3','3cf386ed-769f-4867-8d8b-608e47d1834c',100,'text','**Sau cuộc gọi chăm sóc sau điều trị thành công (Post-Op Care Validation)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bbfdc4ee-f3bb-4b7a-8570-8ec3251dad57','3cf386ed-769f-4867-8d8b-608e47d1834c',101,'text','Khi nhân sự CSKH (Patient Care Team) thực hiện cuộc gọi kiểm tra sức khỏe đúng các mốc giờ vàng sau điều trị và nhận được câu trả lời đầy hạnh phúc của người bệnh: *“Chị ăn nhai tốt rồi em ơi, không còn ê buốt hay sưng đau gì nữa cả, cảm ơn bác sĩ nhiều nhé!”*. Tín hiệu xác nhận an toàn sinh học này chính là đèn xanh để nhân sự lồng ghép lời mời giới thiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('05b0db33-d10e-41b3-99f0-a7ed70b6452a','3cf386ed-769f-4867-8d8b-608e47d1834c',102,'text','**Khi bệnh nhân chủ động đưa ra tín hiệu khen ngợi trực tiếp (Organic Praise)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('58fef509-964c-47cf-996f-9279746255f9','3cf386ed-769f-4867-8d8b-608e47d1834c',103,'text','Đội ngũ trực sàn (Lễ tân, Trợ thủ, Bác sĩ) bắt buộc phải thuộc lòng bộ lọc nhận diện 4 câu thoại "tín hiệu Referral" kinh điển từ miệng khách hàng để không bỏ lỡ cơ hội:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('910a9a94-39c7-4a0c-9ad0-0b165ae2dce6','3cf386ed-769f-4867-8d8b-608e47d1834c',104,'text','- *“Bác sĩ Vinh thực hiện thao tác nhẹ tay quá, thế mà trước đây mình cứ sợ đau không dám đi.”*- *“Nha khoa mình tư vấn kỹ lưỡng, chi phí rõ ràng chứ không mập mờ như mấy bên khác.”*- *“Bước vào đây mình thấy yên tâm và thoải mái hơn hẳn phòng khám cũ gần nhà.”*- *“Răng đẹp thế này để về mình giới thiệu mấy chị em cùng công ty qua đây làm luôn.”*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('212eeabb-c839-4abe-a4e9-18ee1acd2ce4','3cf386ed-769f-4867-8d8b-608e47d1834c',105,'text','**Khi bệnh nhân quay lại tái khám định kỳ đúng hẹn (Recall Loyalty Signal)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d44f4c82-c27a-4f7c-88db-36a2635a4902','3cf386ed-769f-4867-8d8b-608e47d1834c',106,'text','Việc bệnh nhân chủ động sắp xếp thời gian quay lại phòng khám đúng chu kỳ 6 tháng để cạo vôi răng hoặc kiểm tra khớp cắn chứng tỏ họ đánh giá cao giá trị bảo trì sức khỏe của phòng khám. Nhóm này có độ gắn bó cao, phù hợp để đưa vào chương trình Referral một cách nhẹ nhàng, tinh tế.',NULL,NULL,NULL,NULL,NULL);
