INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1169a780-d8e6-41b8-944d-43b7f1fd0f17','28-referral-os','f362cbc9-458f-428a-ae25-d7525b2335ce',4,'LỚP 3: Referral Offer - Thiết Kế Cơ Chế Đặc Quyền Và Đòn Bẩy Tri Ân Tinh Tế','lop-3-referral-offer-thiet-ke-co-che-ac-quyen-va-on-bay-tri-an-tinh-te',25,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('bd98bfdd-3d0c-45fd-9448-e84c40dc4dda','28-referral-os','1169a780-d8e6-41b8-944d-43b7f1fd0f17',5,'Nguyên Tắc Cốt Lõi: Triệt Tiêu Tư Duy Thương Mại Hóa Y Khoa Thô Bạo','nguyen-tac-cot-loi-triet-tieu-tu-duy-thuong-mai-hoa-y-khoa-tho-bao',26,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('345e290d-9644-4242-bf69-a37a350c4714','bd98bfdd-3d0c-45fd-9448-e84c40dc4dda',109,'text','Một cơ chế khuyến khích giới thiệu (Referral Offer) sai lầm là cố tình chi tiền mặt trực tiếp hay trích tỷ lệ phần trăm hoa hồng thô bạo cho người giới thiệu. Trong ngành y tế nói chung và nha khoa nói riêng, cách làm này sẽ ngay lập tức làm hạ thấp uy tín chuyên môn của Bác sĩ, kích hoạt cơ chế đề phòng của khách hàng và biến hành vi lan tỏa giải pháp tử tế thành mô hình bán hàng đa cấp biến tướng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6f0a6718-5d6e-47dc-bee2-33d2824e4198','bd98bfdd-3d0c-45fd-9448-e84c40dc4dda',110,'text','Một Referral Offer xuất sắc phải được thiết kế dựa trên nguyên lý: *Tặng lý do và trao đặc quyền chăm sóc sức khỏe, thay vì mua chuộc bằng tiền*. Hệ thống kiểm soát việc thiết kế ưu đãi dựa trên 5 kiến trúc nền tảng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8c7f790d-2594-4252-a69d-ed41ba3f4d9f','bd98bfdd-3d0c-45fd-9448-e84c40dc4dda',111,'text','- **Dễ hiểu tuyệt đối:** Luật chơi tối giản, khách hàng không cần phải tính toán các điều kiện phức tạp.- **Có lợi thiết thực cho người được giới thiệu:** Người mới bước vào sàn phải được nhận những giá trị vượt trội để xóa bỏ rào cản ma sát đầu phễu.- **Tôn vinh và trân trọng người giới thiệu:** Phần quà tri ân phải mang lại sự hãnh diện, danh giá cho vị thế cá nhân của người cũ.- **Bảo vệ uy tín chuyên môn:** Mọi ưu đãi phải xoay quanh trục giá trị cốt lõi là bảo trì sức khỏe răng miệng, không giảm giá vô tội vạ làm giảm định vị thương hiệu cao cấp tại thị trường Hà Nội.- **Số hóa trọn vẹn trên CRM:** Toàn bộ hạn mức, thời hạn áp dụng của ưu đãi phải được tự động hóa truy vết, không quản lý thủ công bằng giấy tờ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e8d55254-7311-4902-9952-395dc7e9f021','28-referral-os','1169a780-d8e6-41b8-944d-43b7f1fd0f17',5,'Phân Rã Năm Mô Hình Referral Offer Ứng Dụng Thực Địa','phan-ra-nam-mo-hinh-referral-offer-ung-dung-thuc-ia',27,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('802d25bb-a0dd-4520-b18f-8235caf6a7b0','e8d55254-7311-4902-9952-395dc7e9f021',112,'text','Hệ thống chia nhỏ cơ chế tri ân thành 5 danh mục giải pháp, tương thích với từng tệp khách hàng và giai đoạn điều trị khác nhau trên hệ thống CRM:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2481b7c8-2ea6-47d3-a4ca-869741c0ae15','e8d55254-7311-4902-9952-395dc7e9f021',113,'text','**6.1 Family Care Offer (Giải pháp Chăm sóc Nha khoa Gia đình)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('56cd069c-d5c8-41e2-b90c-1e2184797199','e8d55254-7311-4902-9952-395dc7e9f021',114,'text','- **Đối tượng áp dụng:** Bệnh nhân cũ giới thiệu trực tiếp các thành viên ruột thịt trong gia đình (vợ/chồng, bố mẹ, con cái).- **Cơ chế vận hành:** Khi người nhà đến sàn, phòng khám miễn phí 100% chi phí khám tổng quát, chụp phim 3D CT Cone Beam tầm soát biến chứng xương và thiết lập kế hoạch điều trị cá nhân hóa miễn phí.- **Phân khúc dịch vụ tương thích:** Nha khoa tổng quát, chỉnh nha sớm cho trẻ em, bọc răng sứ cho thế hệ trung niên, và cắm ghép Implant cho người cao tuổi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('276ffe9f-518c-4d5c-80ac-da0ef25e3c10','e8d55254-7311-4902-9952-395dc7e9f021',115,'text','**6.1 Thank You Gift (Quà tặng Tri ân Danh giá)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('37aa1065-1551-4ff5-b8d7-e3766ab9d471','e8d55254-7311-4902-9952-395dc7e9f021',116,'text','- **Đối tượng áp dụng:** Gửi tặng riêng cho người giới thiệu ngay sau khi người được họ giới thiệu hoàn tất buổi hẹn thăm khám đầu tiên hoặc ký duyệt phác đồ chính thức tại quầy.- **Danh mục quà tặng vật lý và dịch vụ sạch bảo vệ y khoa:**Suất cạo vôi răng, đánh bóng và chăm sóc nướu định kỳ miễn phí bằng công nghệ sóng siêu âm không đau.- E-Voucher đặc quyền chăm sóc răng miệng trị giá cố định áp dụng cho lần điều trị tiếp theo của chính họ.- Bộ quà tặng sản phẩm vệ sinh răng miệng cao cấp (máy tăm nước tiêu chuẩn nha khoa, bàn chải điện, kem đánh răng chuyên dụng bảo vệ men răng).- Cộng điểm thưởng số hóa trên hệ thống để nâng hạng thẻ thành viên VIP của thương hiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0fcd313d-9ea9-4a6a-afe3-2b9ca4bdbfea','e8d55254-7311-4902-9952-395dc7e9f021',117,'text','**6.2 Dual-Side Offer (Đòn bẩy Lợi ích Song phương - Khuyên dùng)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4f22cb32-d7fe-4a08-8769-4ab737fa1e21','e8d55254-7311-4902-9952-395dc7e9f021',118,'text','- **Đối tượng áp dụng:** Mô hình tối ưu nhất để triệt tiêu hoàn toàn cảm giác ái ngại hay cảm giác "kiếm lợi từ người quen" của khách hàng cũ. Thiết lập cán cân lợi ích công bằng cho cả hai đầu mối.- **Cơ chế vận hành:***Đầu Người được giới thiệu (Referee):* Nhận đặc quyền ưu tiên đặt lịch hẹn ở phòng VIP, miễn phí tầm soát cận lâm sàng đầu vào và nhận mã ưu đãi giảm trực tiếp 10% cho dịch vụ điều trị đầu tiên.- *Đầu Người giới thiệu (Referrer):* Nhận gói bảo trì răng chuyên sâu hoặc quà tặng sức khỏe có giá trị tương xứng từ phòng khám sau khi người thân của họ hoàn tất giao dịch tài chính tại sàn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3285cff3-fb8e-41de-8544-d80f1222a3d8','e8d55254-7311-4902-9952-395dc7e9f021',119,'text','6.3 Community Referral Offer (Liên minh Cộng đồng và Doanh nghiệp)',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e9ef5a68-40ed-4426-90cd-3c2c680bee80','e8d55254-7311-4902-9952-395dc7e9f021',120,'text','- **Đối tượng áp dụng:** Mở rộng biên độ tăng trưởng sang nhóm khách hàng thuộc tổ chức doanh nghiệp, trường học quốc tế, câu lạc bộ hoặc các cộng đồng theo dõi digital brand `Thích Làm Răng`.- **Cơ chế vận hành:** Thiết lập các gói khám sức khỏe răng miệng định kỳ cho toàn bộ nhân sự công ty đối tác chiến lược; tổ chức các buổi Talkshow chia sẻ kiến thức y khoa sạch miễn phí cho phụ huynh học sinh; phát hành mã định danh ưu đãi riêng cho thành viên thuộc các hội nhóm chất lượng cao tại Hà Nội.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b6f7f2c3-b0f3-4a85-9f3c-016cbca82344','e8d55254-7311-4902-9952-395dc7e9f021',121,'text','6.3 VIP Patient Club (Đặc quyền Tối cao cho Nhóm Tinh hoa)',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e2afa82c-c003-48da-82b3-61fb54a3012c','e8d55254-7311-4902-9952-395dc7e9f021',122,'text','- **Đối tượng áp dụng:** Tệp bệnh nhân thuộc Nhóm D (VIP Patient), đã thực hiện các ca đại phẫu có chi phí lớn hoặc là những người liên tục mang lại nguồn khách Referral chất lượng cao cho phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3933625c-3eb5-4d40-949c-b8c0d6cbafb1','e8d55254-7311-4902-9952-395dc7e9f021',123,'text','**Hệ thống đặc quyền trọn đời nâng cấp vị thế khách hàng:**- Hưởng quyền ưu tiên tuyệt đối khi đặt lịch hẹn trên ghế nha, bỏ qua hoàn toàn thời gian chờ đợi tại sảnh.- Hệ thống CRM tự động kích hoạt chế độ nhắc lịch và theo dõi sức khỏe sinh học cá nhân hóa 1-1 do Trợ lý y khoa riêng phụ trách.- Quà tặng thiết kế độc bản và hoa tươi gửi đến tận nhà vào ngày sinh nhật.- Hưởng quyền lợi mở rộng: Người thân đi cùng họ đến khám luôn mặc định được tiếp đón theo tiêu chuẩn VIP Club.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e2eb4c06-b0db-4d73-8ac3-ee335395342b','28-referral-os','1169a780-d8e6-41b8-944d-43b7f1fd0f17',5,'Mô Hình Hoạt Động Của Cơ Chế Chia Sẻ Không rào cản (Easy Sharing)','mo-hinh-hoat-ong-cua-co-che-chia-se-khong-rao-can-easy-sharing',28,'[]');
