INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e33cda05-d623-4c50-afde-c2644a7e0213','e2eb4c06-b0db-4d73-8ac3-ee335395342b',127,'text','*"Phần thưởng lớn nhất mà một bệnh nhân nhận được khi giới thiệu người thân đến nha khoa Thích Làm Răng không phải là một mã giảm giá, mà là cái gật đầu mãn nguyện và lời cảm ơn từ chính người thân của họ sau khi được Bác sĩ Vinh điều trị khỏi bệnh. Hãy thiết kế những ưu đãi tinh tế để nâng cao giá trị của lời cảm ơn đó."*',NULL,NULL,NULL,NULL,NULL);
