INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e126e5f0-b439-48d6-be3f-1d2c35899efc','28-referral-os','f362cbc9-458f-428a-ae25-d7525b2335ce',4,'LỚP 5: Referral Tracking - Hạ Tầng Số Hóa Và Truy Vết Nguồn Giới Thiệu','lop-5-referral-tracking-ha-tang-so-hoa-va-truy-vet-nguon-gioi-thieu',30,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f01a06fb-8e99-49a0-a7f8-503cf9aa7b67','28-referral-os','e126e5f0-b439-48d6-be3f-1d2c35899efc',5,'Tư Duy Quản Trị: Nếu Không Đo Lường, Bạn Không Thể Quản Trị','tu-duy-quan-tri-neu-khong-o-luong-ban-khong-the-quan-tri',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0365965f-1c04-4bd3-8bca-d98d90699514','f01a06fb-8e99-49a0-a7f8-503cf9aa7b67',129,'text','Lý do lớn nhất khiến các chiến dịch xin lời giới thiệu tại đa số nha khoa thất bại sau vài tuần triển khai là do **đứt gãy hạ tầng theo vết (Tracking)**. Khi không có công cụ định danh, dữ liệu ghi nhận bị phân tán: Lễ tân quên nhập nguồn, CSKH không biết ai giới thiệu để gửi quà tri ân, quản lý không đo lường được hiệu quả của từng chương trình, và bác sĩ không biết nhân sự nào đang tích cực kích hoạt Referral trên sàn. Trạng thái vận hành mờ mịt này sẽ triệt tiêu động lực của cả đội ngũ lẫn khách hàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cb5424b6-778b-4d0f-b378-620a35e798c5','f01a06fb-8e99-49a0-a7f8-503cf9aa7b67',130,'text','Lớp **Referral Tracking** được thiết kế như một hệ thống thu thập và xử lý dữ liệu khép kín trên CRM. Chúng tôi số hóa mọi điểm chạm giới thiệu thành các trường dữ liệu cứng, cho phép ban quản trị tại Hà Nội nhìn rõ "cây phả hệ lòng tin" của từng bệnh nhân, từ đó ra quyết định điều hành dựa trên các con số thực chứng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a508aca6-ec2a-4c17-9dbd-0a79e3b29e68','28-referral-os','e126e5f0-b439-48d6-be3f-1d2c35899efc',5,'Kiến Trúc Mã Định Danh Và Liên Kết Dữ Liệu Trên CRM','kien-truc-ma-inh-danh-va-lien-ket-du-lieu-tren-crm',32,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6c17e700-73f3-41e9-a982-c5ea828acda2','a508aca6-ec2a-4c17-9dbd-0a79e3b29e68',131,'text','Để triệt tiêu hoàn toàn rủi ro sót nguồn, hệ thống CRM thiết lập cơ chế đồng bộ dữ liệu tự động thông qua cấu trúc **Mã định danh liên kết (Referral ID Mapping)**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f9a5a427-9b48-43b3-ad30-86d5909399e8','a508aca6-ec2a-4c17-9dbd-0a79e3b29e68',132,'image',NULL,'book/28-referral-os/273d73b4-2f93-4c74-a402-9c2206016911-img13.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('60637e2d-cab1-456f-ac3d-a92809c4e425','a508aca6-ec2a-4c17-9dbd-0a79e3b29e68',133,'text','Khi hồ sơ bệnh nhân mới (ID-11112) phát sinh bất kỳ giao dịch doanh thu nào tại sàn, hệ thống sẽ tự động trích xuất một Payload thông báo về tài khoản của chuyên viên CSKH để kích hoạt quy trình tri ân cho bệnh nhân cũ (ID-9999).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2e244ab2-33d3-43d4-ab7c-ef6387929928','28-referral-os','e126e5f0-b439-48d6-be3f-1d2c35899efc',5,'Ma Trận Phương Pháp Theo Vết Đa Kênh (Omnichannel Tracking Matrix)','ma-tran-phuong-phap-theo-vet-a-kenh-omnichannel-tracking-matrix',33,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('128a4d67-75bc-4426-9918-f8e7fa42e606','2e244ab2-33d3-43d4-ab7c-ef6387929928',134,'text','Hệ thống ghi nhận nguồn khách giới thiệu thông qua cả hai kênh vật lý (Offline) và kỹ thuật số (Online) để đảm bảo không ma sát đối với người bệnh:',NULL,NULL,NULL,NULL,NULL);
