INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f8a7d1e6-e431-4776-9371-7ddc5a6a54a4','b30168eb-c30c-4499-91f5-2ab729a89f31',135,'text','Hằng tuần, hệ thống tự động xuất biểu đồ báo cáo quản trị (Dashboard) để giúp chủ doanh nghiệp kiểm soát 4 chiều thông tin lõi:',NULL,NULL,NULL,NULL,NULL);
