INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a9c84a5b-f7f5-4e07-b67a-d425d62476a5','b30168eb-c30c-4499-91f5-2ab729a89f31',137,'text','Danh sách những bệnh nhân mang lại giá trị gián tiếp cao nhất cho phòng khám. CRM xếp hạng dựa trên:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e0aa2a36-e83c-4ffe-a212-4183c5084230','b30168eb-c30c-4499-91f5-2ab729a89f31',138,'text','- Tổng số lượng hồ sơ (N) được giới thiệu đến khám thực tế.- Tổng giá trị doanh thu thực thu (V) phát sinh từ nhánh cây giới thiệu đó.- *Hành động điều hành:* Quản lý cơ sở chủ động gọi điện tri ân, gửi quà VIP cuối năm để giữ chân nhóm mỏ neo này.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d4cd4065-2bf0-4e0c-a00d-522b46ba6446','b30168eb-c30c-4499-91f5-2ab729a89f31',139,'text','**4.2 Báo cáo Hiệu suất Nhân sự (Staff Activation Report)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('083637a6-cea9-4da8-b12a-210ec46e6c84','b30168eb-c30c-4499-91f5-2ab729a89f31',140,'text','Đo lường năng lực và kỷ luật vận hành kịch bản của từng nhân sự tại cơ sở:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0b0b8322-fa4c-40bd-a554-d62b031d97ef','b30168eb-c30c-4499-91f5-2ab729a89f31',141,'text','- Tỷ lệ đưa ra lời mời và trao thẻ đặc quyền thành công của từng Lễ tân/Trợ thủ.- *Hành động điều hành:* Khen thưởng trực tiếp cho nhân sự có chỉ số kích hoạt cao; tái đào tạo bộ Script giao tiếp cho những nhân sự có chỉ số dưới chuẩn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1a846c9c-0000-4781-9178-70adf93084f9','b30168eb-c30c-4499-91f5-2ab729a89f31',142,'text','**4.3 Báo cáo Doanh thu trên Chi phí (ROI Campaign Analysis)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bfe19190-b15d-461b-b040-006745a32db3','b30168eb-c30c-4499-91f5-2ab729a89f31',143,'text','Kiểm soát tính kinh tế của các chương trình Offer:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dd7af3a8-f58d-4129-891c-948df0e978d8','b30168eb-c30c-4499-91f5-2ab729a89f31',144,'text','- Công thức tính toán hiệu quả tài chính:- \\text{ROI}_{\\text{Referral}} = \\frac{\\text{Tổng doanh thu thực thu từ nguồn Referral} - \\text{Tổng chi phí quà tặng tri ân}}{\\text{Tổng chi phí quà tặng tri ân}}
- *Ngưỡng tiêu chuẩn:* Chỉ số \\text{ROI}_{\\text{Referral}} trong hệ thống Dental Empire bắt buộc phải đạt từ **\\ge 500\\%** trở lên (vượt trội hoàn toàn so với mức ROI trung bình của kênh chạy quảng cáo Paid Ads thông thường).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('63e66fd1-e418-4df2-9abd-2bf90cb13849','28-referral-os','e126e5f0-b439-48d6-be3f-1d2c35899efc',5,'Mỏ Neo Toán Học: Hệ Số Lan Truyền Dữ Liệu Bệnh Nhân (K-factor)','mo-neo-toan-hoc-he-so-lan-truyen-du-lieu-benh-nhan-k-factor',35,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e6616d4e-99a2-41a9-8f3c-ab938024f804','63e66fd1-e418-4df2-9abd-2bf90cb13849',145,'image',NULL,'book/28-referral-os/cfdc7fd8-825f-44aa-ac1c-a51e35841c46-img14.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('29f5bed2-33d0-4e80-9f71-1a98bdc3b781','63e66fd1-e418-4df2-9abd-2bf90cb13849',146,'text','**Mantra điều hành Referral Tracking:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dd3b2642-d061-4409-921c-8ecdbc77ca18','63e66fd1-e418-4df2-9abd-2bf90cb13849',147,'text','*"Vận hành hệ thống giới thiệu mà không có công cụ tracking chuẩn xác giống như việc bạn đổ nước vào một chiếc xô thủng đáy. Bạn sẽ sớm làm mất lòng tin của những bệnh nhân trung thành nhất chỉ vì sự hay quên của nhân sự. Hãy số hóa mọi lời giới thiệu để biến lòng tin thành những con số biết nói."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('43ef4815-5687-4be4-bbe9-ef34c35a17e6','28-referral-os','f362cbc9-458f-428a-ae25-d7525b2335ce',4,'LỚP 6: Referral Care - Quy Trình Chăm Sóc Kép Dual-Care','lop-6-referral-care-quy-trinh-cham-soc-kep-dual-care',36,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4b7aae5f-207e-40ad-9e9b-d6b999644ee7','43ef4815-5687-4be4-bbe9-ef34c35a17e6',148,'text','Một sai lầm chí mạng khiến hệ thống giới thiệu của các phòng khám truyền thống bị gãy đổ sau vài ca đầu tiên là tư duy: *Coi người được giới thiệu như một Lead quảng cáo thông thường*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ed8ea87b-60bc-4dec-8e51-0ab42de38677','43ef4815-5687-4be4-bbe9-ef34c35a17e6',149,'text','Hành trình Referral không kết thúc khi phòng khám nhận được thông tin số điện thoại của khách hàng mới. Nếu người được giới thiệu đến sàn và gặp phải trải nghiệm kém (chờ đợi lâu, bác sĩ tư vấn hời hợt, phụ tá cọc cằn), người giới thiệu sẽ lập tức bị tổn thương uy tín cá nhân với bạn bè, người thân của họ. Khi đó, dòng chảy giới thiệu của hồ sơ mỏ neo đó sẽ bị khóa vĩnh viễn. Nhóm Referral Lead bắt buộc phải được đưa vào một chế độ chăm sóc đặc biệt (Dual-Care) để bảo vệ danh dự cho người giới thiệu và chuyển hóa người mới thành đại sứ tiếp theo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2e072368-d8d3-4a3c-abb1-9c3ec59b3627','28-referral-os','43ef4815-5687-4be4-bbe9-ef34c35a17e6',5,'Năm Nguyên Tắc Vàng Trong Tiếp Cận Referral Lead','nam-nguyen-tac-vang-trong-tiep-can-referral-lead',37,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('952fe263-bad8-414f-b169-08da5824d044','2e072368-d8d3-4a3c-abb1-9c3ec59b3627',150,'text','Trước khi nhấc máy liên hệ hoặc đón tiếp khách hàng tại cơ sở Hà Nội, nhân sự CSKH và Lễ tân phải tuân thủ tuyệt đối 5 nguyên tắc:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e6354f36-c7fa-41ee-9d04-6b5818758eef','2e072368-d8d3-4a3c-abb1-9c3ec59b3627',151,'text','- **Nhanh hơn:** Tiếp nhận và xử lý lịch hẹn của khách Referral trong vòng dưới 5 phút kể từ khi phát sinh Lead trên CRM.- **Cá nhân hóa hơn:** Luôn luôn lồng ghép tên và mối quan hệ của người giới thiệu vào trong mọi câu thoại giao tiếp.- **Tử tế hơn:** Đón tiếp bằng sự tôn trọng tối cao, phục vụ tại không gian phòng VIP để người cũ cảm thấy tự hào vì đã giới thiệu.- **Rõ ràng hơn:** Tư vấn phác đồ y khoa dựa trên sự minh bạch, bóc tách chi phí trọn gói, không mập mờ, không gài bẫy doanh thu.- **Báo đáp đúng lúc:** Gửi lời tri ân và kích hoạt phần thưởng cho người giới thiệu ngay khi người mới vừa hoàn tất khâu check-in lâm sàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('859f09fb-e13f-4deb-8d39-0709bba21373','28-referral-os','43ef4815-5687-4be4-bbe9-ef34c35a17e6',5,'Quy Trình Đường Ống Chăm Sóc Kép Đa Điểm Chạm 5 Bước','quy-trinh-uong-ong-cham-soc-kep-a-iem-cham-5-buoc',38,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('14f389d0-fa64-4c37-a49c-02d4ac23569d','859f09fb-e13f-4deb-8d39-0709bba21373',152,'text','Đường ống điều hành xử lý Referral Lead từ lúc tiếp nhận thông tin cho đến khi đóng chu kỳ tri ân được thực thi nghiêm ngặt theo đúng trình tự dưới đây:',NULL,NULL,NULL,NULL,NULL);
