INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('76f91400-6b25-457b-a765-5955708cbf3e','859f09fb-e13f-4deb-8d39-0709bba21373',155,'text','Khi gọi điện hoặc nhắn tin thiết lập lịch hẹn lần đầu, chuyên viên CSKH bắt buộc phải sử dụng kịch bản mỏ neo để kéo gần khoảng cách, xóa bỏ sự đề phòng của khách hàng mới.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5160b307-77ef-43b7-a6da-23e9f6f19d42','859f09fb-e13f-4deb-8d39-0709bba21373',156,'text','**2.2. Cá nhân hóa lời chào và thiết lập đặc quyền:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0b8c757a-e0cc-41ee-a308-c6461315677d','859f09fb-e13f-4deb-8d39-0709bba21373',157,'text','*Chặng 2 - Truyền dẫn uy tín bác sĩ.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('09b7e7fd-0206-46ce-bf2e-a6b0bf3ec026','859f09fb-e13f-4deb-8d39-0709bba21373',158,'text','Nhắc lại trải nghiệm thành công của người cũ tại phòng khám để chuyển di lòng tin sang cho năng lực chuyên môn của Bác sĩ Vinh, tạo tâm lý an tâm tuyệt đối cho người mới.',NULL,NULL,NULL,NULL,NULL);
