INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bb2385b5-8b13-4c6d-a11d-f59e66ebb178','859f09fb-e13f-4deb-8d39-0709bba21373',160,'text','*Chặng 3 - Thực thi lâm sàng tử tế.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('23878866-ba76-4baf-b301-b487b715fa29','859f09fb-e13f-4deb-8d39-0709bba21373',161,'text','Tuyệt đối không áp dụng các chiêu trò ép chốt sale nhanh, tư vấn dồn dập đối với nhóm khách này. Nhiệm vụ của Bác sĩ và chuyên viên TCO là bảo vệ danh dự cho người giới thiệu bằng sự trung thực y khoa: giải thích bệnh lý rõ ràng, đưa giải pháp tối ưu nhất, minh bạch chi phí trọn gói và sẵn sàng cho khách hàng thời gian suy nghĩ, cân nhắc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('08534857-7ec0-4a9a-8b49-d02cae1d64ce','859f09fb-e13f-4deb-8d39-0709bba21373',162,'text','**2.4. Báo cáo trạng thái chung cho người giới thiệu:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ccc7fbbe-b75d-431f-a2a3-52a1bcabb135','859f09fb-e13f-4deb-8d39-0709bba21373',163,'text','*Chặng 4 - Cập nhật an toàn số.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d51eaf6b-8acc-4e36-a36a-5fcd7ab9f7da','859f09fb-e13f-4deb-8d39-0709bba21373',164,'text','Ngay sau khi người mới hoàn tất buổi khám, hệ thống CRM tự động kích hoạt tin nhắn gửi đến người giới thiệu. Tuân thủ nguyên tắc bảo mật thông tin y tế cá nhân: Tuyệt đối không tiết lộ chi tiết bệnh lý lâm sàng hay giá tiền phác đồ của người mới, chỉ gửi lời cảm ơn và xác nhận trạng thái tiếp đón chu đáo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('24c68e56-dec7-4175-861d-f2359b7411e0','859f09fb-e13f-4deb-8d39-0709bba21373',165,'text','**2.5. Gửi lời cảm ơn kèm Quà tặng Tri ân:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8036f8e5-1e03-447e-914a-bf7ea358674e','859f09fb-e13f-4deb-8d39-0709bba21373',166,'text','*Chặng 5 - Kích hoạt đòn bẩy báo đáp.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d0004ef4-46c3-477e-bc34-74df6ceb89b7','859f09fb-e13f-4deb-8d39-0709bba21373',167,'text','Khi khách hàng mới phát sinh giao dịch thanh toán hoặc ký duyệt phác đồ chính thức, chuyên viên CSKH lập tức liên hệ với người giới thiệu để trao gửi phần quà cảm ơn tinh tế theo đúng danh mục Offer đã thiết kế tại Mục 22.7.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('102a1330-897e-492a-94d7-1afb278c55c5','859f09fb-e13f-4deb-8d39-0709bba21373',168,'text','**Mantra điều hành Referral Care:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5ebc6ba5-1f05-426f-a458-a67c16cee0dc','859f09fb-e13f-4deb-8d39-0709bba21373',169,'text','*"Hành vi giới thiệu là một sự đánh cược bằng danh dự. Người bệnh trao cho chúng ta người thân của họ, tức là họ đang đặt uy tín cá nhân của họ vào tay đội ngũ Thích Làm Răng. Hãy chăm sóc người được giới thiệu bằng một tiêu chuẩn y khoa tử tế nhất để người cũ luôn cảm thấy hãnh diện vì quyết định giới thiệu của mình."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b0266772-400d-48ad-9013-9ca5e919642e','28-referral-os','f362cbc9-458f-428a-ae25-d7525b2335ce',4,'LỚP 7: Referral Flywheel - Vòng Lặp Tăng Trưởng Tự Thân Giới Thiệu','lop-7-referral-flywheel-vong-lap-tang-truong-tu-than-gioi-thieu',39,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2a90f3df-9c49-49bf-a334-df6a853c3d26','28-referral-os','b0266772-400d-48ad-9013-9ca5e919642e',5,'Tư Duy Vận Hành: Từ Phễu Tuyến Tính Sang Bánh Đà Sự Thật','tu-duy-van-hanh-tu-pheu-tuyen-tinh-sang-banh-a-su-that',40,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d4f981e4-7987-493e-9446-3c23caf3dd74','2a90f3df-9c49-49bf-a334-df6a853c3d26',170,'text','Sự khác biệt lớn nhất giữa một phòng khám đốt tiền quảng cáo và một đế chế nha khoa bền vững nằm ở cách nhìn nhận về dòng chảy khách hàng. Mô hình phễu Marketing truyền thống (Đổ tiền Ads \\rightarrow Có Lead \\rightarrow Chốt Sale \\rightarrow Hết chu kỳ) là một đường thẳng tiêu tốn tài nguyên. Khi dừng nạp tiền vào quảng cáo, nguồn khách mới ngay lập tức bị ngắt ngọn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4d642b5a-2bcf-4950-b633-a7aa437d09bd','2a90f3df-9c49-49bf-a334-df6a853c3d26',171,'text','Lớp **Referral Flywheel** chuyển dịch toàn bộ bộ máy vận hành sang mô hình bánh đà tự sinh động năng. Điểm kết thúc của một ca điều trị thành công lại chính là điểm khởi đầu kích nổ cho một chuỗi ca điều trị mới. Khi bánh đà này được đẩy qua ngưỡng ma sát ban đầu, nó sẽ tự quay nhanh hơn dựa trên nguồn năng lượng tích lũy từ lòng tin của bệnh nhân, giúp phòng khám tăng trưởng vượt bậc mà không phụ thuộc vào các thuật toán phân phối của nền tảng quảng cáo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('27f3f8c2-b059-4f79-bf40-89854f08ed17','28-referral-os','b0266772-400d-48ad-9013-9ca5e919642e',5,'Giải Mã 8 Mắt Xích Của Bánh Đà Tăng Trưởng Đồng Bộ','giai-ma-8-mat-xich-cua-banh-a-tang-truong-ong-bo',41,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a33a4a13-4d98-4a08-b2c2-49259582ac7a','27f3f8c2-b059-4f79-bf40-89854f08ed17',172,'text','Hệ thống quản trị CRM giám sát sự chuyển hóa động năng thông qua 8 mắt xích khép kín không đứt gãy:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e260b2e9-47de-4720-8eed-9fadaa95b042','27f3f8c2-b059-4f79-bf40-89854f08ed17',173,'image',NULL,'book/28-referral-os/0bdbaac9-6ce3-4c96-b02d-3c0e1d38001a-img15.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ea62c8ab-85ac-4231-84fe-f887b1b07615','27f3f8c2-b059-4f79-bf40-89854f08ed17',174,'text','- **Vòng lặp tái kích hoạt:** Chỉ số Trust tăng vọt (Mắt xích 8) lại quay ngược trở lại gia cố cho Mắt xích 1, khiến cho trải nghiệm của những bệnh nhân tiếp theo càng ngày càng trở nên dễ dàng và uy tín hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d3233553-e8cd-45b3-8416-9c8b36fdfc0b','28-referral-os','b0266772-400d-48ad-9013-9ca5e919642e',5,'Sáu Giá Trị Thực Chứng Tích Lũy Của Referral Flywheel','sau-gia-tri-thuc-chung-tich-luy-cua-referral-flywheel',42,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f28c3bec-af30-4745-8cc1-d88cae6d826e','d3233553-e8cd-45b3-8416-9c8b36fdfc0b',175,'text','Một chiến dịch quảng cáo trả phí chỉ có thể mang lại dòng tiền ngắn hạn, nhưng **Referral Flywheel** mang lại cho phòng khám 6 loại tài sản thực chứng (The Six Structural Truths). Đây là vũ khí tối thượng giúp thương hiệu đè bẹp các đối thủ cạnh tranh bằng sự chân thật, giữa bối cảnh thị trường nha khoa đang bị bão hòa bởi các chiêu trò truyền thông phóng đại:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c9ecee45-9601-42a3-8c5e-1d2c369d6f60','d3233553-e8cd-45b3-8416-9c8b36fdfc0b',176,'text','**3.1 Case lâm sàng thật (Real Clinical Cases)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('589accbf-0d91-4e7b-ba6c-2fb1886e2b7c','d3233553-e8cd-45b3-8416-9c8b36fdfc0b',177,'text','Hệ thống thu hoạch liên tục các ca lâm sàng đa dạng, từ chỉnh nha phức tạp đến phục hình Implant chuyên sâu. Đây là minh chứng đanh thép nhất cho năng lực y khoa của Bác sĩ Vinh và cộng sự tại Hà Nội, không thể làm giả bằng các kỹ thuật photoshop hay mua tư liệu nước ngoài.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('adb802bd-c91d-44a6-8bd7-4ce6b648db5a','d3233553-e8cd-45b3-8416-9c8b36fdfc0b',178,'text','**3.2 Đánh giá thật (Real Reviews)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6669b244-541e-4fa6-83c3-4a745495fc76','d3233553-e8cd-45b3-8416-9c8b36fdfc0b',179,'text','Những dòng nhận xét 5 sao trên Google Maps, những bình luận chứa đầy sự biết ơn dưới video TikTok đều đến từ tài khoản người dùng thật, định vị thật. Chúng đóng vai trò là những bộ lọc niềm tin khách quan nhất giúp gỡ bỏ hoàn toàn sự e dè của khách hàng mới khi tra cứu thông tin về phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2d106298-6cec-4f95-9d45-71bf20103803','d3233553-e8cd-45b3-8416-9c8b36fdfc0b',180,'text','**3.3 Nội dung thật (Real Media Content)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ce93be25-cc5f-47ea-9496-8277dd3b2584','d3233553-e8cd-45b3-8416-9c8b36fdfc0b',181,'text','Nguồn nguyên liệu sản xuất nội dung (Content Production) được sinh ra hằng ngày ngay tại phòng điều trị VIP. Những thước phim ngắn ghi lại khoảnh khắc tháo niềng, những bộ ảnh Trước/Sau chân thực chính là những nội dung có tỷ lệ chuyển đổi và tương tác tự nhiên cao nhất trên kênh `@thichlamrang`.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('54dfd649-047c-4d41-93cb-864c86e4be58','d3233553-e8cd-45b3-8416-9c8b36fdfc0b',182,'text','**3.4 Câu chuyện thật (Real Patient Stories)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c98640f3-9378-41e3-817c-b6075cd5af51','d3233553-e8cd-45b3-8416-9c8b36fdfc0b',183,'text','Con người không mua dịch vụ nha khoa, họ mua sự dịch chuyển của số phận được kể qua các câu chuyện. Câu chuyện về một người thay đổi sự tự tin, tìm được công việc tốt hơn sau khi có nụ cười mới chính là sợi dây kết nối cảm xúc mạnh mẽ nhất, chạm đến nỗi đau của hàng ngàn bệnh nhân khác ngoài thị trường.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e4e49654-a006-40af-8bb3-a4b60a1a2c2b','d3233553-e8cd-45b3-8416-9c8b36fdfc0b',184,'text','**3.5 Niềm tin thật (Real Systemic Trust)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2614f77d-1350-4581-a137-fc4e24a11a35','d3233553-e8cd-45b3-8416-9c8b36fdfc0b',185,'text','Mối quan hệ giữa bệnh nhân và phòng khám không còn là quan hệ mua bán sòng phẳng theo kiểu "tiền trao cháo múc". Lòng tin lúc này đã được thử thách qua kết quả lâm sàng và kỷ luật chăm sóc hậu phẫu, tạo nên một mỏ neo uy tín vững chắc bảo vệ danh tiếng phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2984fd24-e91e-4b8a-9a3a-d7d8797fcb94','d3233553-e8cd-45b3-8416-9c8b36fdfc0b',186,'text','**3.6 Cộng đồng thật (Real Brand Community)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c94be8d8-f8e6-4d29-9e19-52b510b90f82','d3233553-e8cd-45b3-8416-9c8b36fdfc0b',187,'text','Mục tiêu tối cao của bánh đà là kết tinh tệp khách hàng cũ thành một bộ tộc những người ủng hộ (Brand Advocates). Họ sẵn sàng giới thiệu cho người thân, tự hào khi nhắc đến thương hiệu và chủ động bảo vệ phòng khám trước các luồng thông tin tiêu cực sai sự thật trên không gian mạng.',NULL,NULL,NULL,NULL,NULL);
