INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('15192d01-c9c6-4bb8-a2b2-07ed12f84490','83e57580-550a-43d6-a997-7e1ba109000b',189,'text','**Mantra điều hành Referral Flywheel:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('397273fa-cf6e-4520-a301-1778dfe906ed','83e57580-550a-43d6-a997-7e1ba109000b',190,'text','*"Quảng cáo trả phí giúp phòng khám sống sót qua từng ngày, nhưng chỉ có bánh đà tăng trưởng giới thiệu dựa trên những giá trị thực chứng mới có thể giúp phòng khám trường tồn qua từng năm. Hãy tập trung tích lũy những giá trị thật: Case thật, Review thật, và Lòng tin thật để giữ cho bánh đà luôn quay đều hằng tháng."*',NULL,NULL,NULL,NULL,NULL);
