INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f4e41367-e220-4c15-b1df-ce422a296e8e','e064fc4b-a4ac-44cf-90fe-4c262373d5e3',191,'text','Bảng điều khiển (Dashboard) dữ liệu chỉ thực sự tạo ra giá trị tăng trưởng khi từng chỉ số hiển thị được gắn chặt với trách nhiệm cá nhân của từng vị trí trong bộ máy. Nếu thiếu sự phân định rõ ràng, Dashboard sẽ nhanh chóng biến thành một bảng số liệu "để xem" mang tính hình thức, không thể kích hoạt các hành động vận hành thực tế tại phòng khám.',NULL,NULL,NULL,NULL,NULL);
