INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d924cb31-82b0-44d0-80c0-9620438ec9ad','738eb252-8d61-4850-bf66-45e59027356a',195,'text','Hệ thống phân định rõ ràng nhân sự chịu trách nhiệm chính (Owner), nhân sự phối hợp thực thi (Contributor) và tần suất kiểm toán cho từng trường dữ liệu trên **Referral Overview Dashboard**:',NULL,NULL,NULL,NULL,NULL);
