INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f583ac3e-9781-461b-bf81-b0e03c947f08','738eb252-8d61-4850-bf66-45e59027356a',198,'text','*"Một con số tụt dốc trên Dashboard không phải là một thông báo để đọc, đó là một mệnh lệnh hành động khẩn cấp được gửi đích danh đến người sở hữu chỉ số. Hãy vận hành hệ thống phân quyền này với kỷ luật thép để đảm bảo mọi lỗ rò rỉ dòng tiền hữu cơ đều được phát hiện và xử lý dứt điểm trong vòng 24 giờ."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8196e2c5-7130-4551-b2d8-a86b44f41107','28-referral-os',NULL,2,'28.7 KPI FRAMEWORK','287-kpi-framework',48,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3ad9efbd-b8b9-42ce-b01f-4ad9fc40bfef','8196e2c5-7130-4551-b2d8-a86b44f41107',199,'text','Hệ thống KPI Framework thiết lập tại chương này chính là chìa khóa để Ban quản trị  dịch chuyển toàn bộ hoạt động tăng trưởng bằng giới thiệu từ trạng thái bản năng, cảm tính sang một hệ thống khoa học có thể kiểm soát, dự báo và quản trị bằng các con số thực chứng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f7eeb21f-9a8e-4662-bc2d-653de38226ac','8196e2c5-7130-4551-b2d8-a86b44f41107',200,'text','Một hệ điều hành **Referral OS** mạnh mẽ tuyệt đối không bao giờ dừng lại ở việc đo lường các chỉ số bề nổi có tính chất "danh hão" như: *Tháng này phòng khám có bao nhiêu khách bảo là được người quen giới thiệu?* Hệ thống bắt buộc phải bóc tách dữ liệu theo chiều sâu, truy vết khép kín hành vi của dòng tiền hữu cơ thông qua các câu hỏi chất vấn hệ thống:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('afbf8c3a-cdda-470f-8112-436e33c18aa3','8196e2c5-7130-4551-b2d8-a86b44f41107',201,'text','- **Ai giới thiệu (Identity Tracking):** Hồ sơ khách cũ nào đang là mỏ neo lòng tin mang lại nhiều khách nhất cho phòng khám?- **Giới thiệu từ nguồn nào (Source Attribution):** Khách đến thông qua Thẻ Đặc Quyền Nụ Cười vật lý tại sảnh Hà Nội hay qua liên kết mã QR cá nhân hóa trên Zalo OA?- **Referral có đến khám không (Show-up Validation):** Tỷ lệ chuyển đổi từ dữ liệu thô sang người thật bước vào sảnh thực địa là bao nhiêu?- **Có thực hiện điều trị không (Conversion Audit):** Năng lực lâm sàng của Bác sĩ Vinh và khâu tư vấn của TCO có chuyển hóa được lòng tin của người mới thành phác đồ thực tế?- **Tạo ra bao nhiêu doanh thu (Financial Impact):** Nhánh cây phả hệ lòng tin này đóng góp bao nhiêu phần trăm vào dòng tiền ròng hằng tháng của cơ sở?- **Người giới thiệu có được cảm ơn không (SLA Care Verification):** Quy trình tri ân (Thank You Gift) đã được kế toán và CSKH phê duyệt phát đi đúng hạn, sòng phẳng chưa?- **Người được giới thiệu có tiếp tục giới thiệu người khác (The Loop Effect):** Bánh đà đã kích nổ thành công để biến một khách hàng mới (Referee) trở thành một đại sứ mới (Referrer) hay chưa?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('571dea3b-e8b5-4aa0-8141-f4c3cebdc21f','28-referral-os','8196e2c5-7130-4551-b2d8-a86b44f41107',4,'Bộ Sổ Tay 10 Chỉ Số KPI Cốt Lõi Của Referral OS','bo-so-tay-10-chi-so-kpi-cot-loi-cua-referral-os',49,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('db8910e6-1015-42a0-9456-4d28fa967792','571dea3b-e8b5-4aa0-8141-f4c3cebdc21f',202,'image',NULL,'book/28-referral-os/746f2166-a03b-4ed3-9097-5031130a57ef-img19.png','image.png','image/png','image.png',NULL);
