INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('50c16618-6cf3-4bfc-a250-b67999d251e1','571dea3b-e8b5-4aa0-8141-f4c3cebdc21f',204,'text','*"Khi bạn đo lường đúng và đủ sâu, bạn sẽ nhận ra lòng tin của bệnh nhân chính là loại tài sản có tỷ suất sinh lời cao nhất trong kinh doanh nha khoa. Thiết lập bộ KPI này chính là cách nha khoa Thích Làm Răng xây dựng Referral OS thành một động cơ tăng trưởng hữu cơ bền vững nhất, đưa thương hiệu thoát khỏi cuộc đua đốt tiền quảng cáo trực tuyến để bứt phá dẫn đầu thị trường."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7c6f567f-448a-44ea-a6f4-b88415cdaa5b','28-referral-os',NULL,2,'28.8 Các Sai Lầm Kinh Điển Khi Triển Khai Referral OS (Systemic Blockers)','288-cac-sai-lam-kinh-ien-khi-trien-khai-referral-os-systemic-blockers',50,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c82d6fa6-fd67-4ef7-a6aa-51af99e9753a','7c6f567f-448a-44ea-a6f4-b88415cdaa5b',205,'text','Một hệ thống giới thiệu khách hàng hữu cơ dù được thiết kế bài bản đến đâu vẫn có thể hoàn toàn tê liệt nếu ban quản trị và nhân sự trực sàn mắc phải những tư duy sai lệch dưới đây. Những sai lầm này hoạt động như những "lực ma sát" trực tiếp kìm hãm, thậm chí đảo chiều động năng của bánh đà tăng trưởng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c08c3458-83c6-435a-8f1a-57faecf2c0ef','28-referral-os','7c6f567f-448a-44ea-a6f4-b88415cdaa5b',3,'Bảng Đối Soát: Triệu Chứng Và Tổn Thất','bang-oi-soat-trieu-chung-va-ton-that',51,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5c371a7e-6d56-46be-8f9d-e7cef6bfb2f5','c08c3458-83c6-435a-8f1a-57faecf2c0ef',206,'text','Ban quản lý cơ sở sử dụng bảng ma trận này để nhận diện nhanh các hành vi lệch chuẩn của nhân sự trong quá trình vận hành thực tế:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8d47cdca-9fb7-4c63-83f0-ac6f818a2182','c08c3458-83c6-435a-8f1a-57faecf2c0ef',207,'image',NULL,'book/28-referral-os/dee14954-1099-42e4-9678-81618310575b-img20.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('03db1af4-b812-4e7f-afdb-f13b42cd4559','28-referral-os','7c6f567f-448a-44ea-a6f4-b88415cdaa5b',3,'Phân Tích Chi Tiết Sáu Lỗ Hổng Và Giải Pháp Sửa Sai Vĩ Mô','phan-tich-chi-tiet-sau-lo-hong-va-giai-phap-sua-sai-vi-mo',52,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7532c6c8-1d25-4916-8021-e48d1146e05f','28-referral-os','03db1af4-b812-4e7f-afdb-f13b42cd4559',4,'Sai lầm 1: Tư duy "Chữa cháy" ngắn hạn (Campaign vs. System)','sai-lam-1-tu-duy-chua-chay-ngan-han-campaign-vs-system',53,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f8ef2c45-4920-4ffe-b173-5e2dc71ab20e','7532c6c8-1d25-4916-8021-e48d1146e05f',208,'text','- **Bản chất:** Lời giới thiệu không phải là một giải pháp tình thế để cứu vãn doanh số khi phòng khám gặp khủng hoảng nguồn khách. Nó là kết quả tích lũy của một hệ thống dịch vụ vận hành bền bỉ hằng ngày.- **Giải pháp Referral OS:** Cấu hình bộ kịch bản và điểm kích hoạt thành quy trình cứng bắt buộc, chạy liên tục 365 ngày trong năm trên CRM bất kể phòng khám đang đông hay vắng khách.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('be57c417-1c49-437d-94f7-d1ca87982d8e','28-referral-os','03db1af4-b812-4e7f-afdb-f13b42cd4559',4,'Sai lầm 2: Ép chín non khi chưa tích lũy thặng dư lòng tin (Premature Asking)','sai-lam-2-ep-chin-non-khi-chua-tich-luy-thang-du-long-tin-premature-asking',54,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c0875a22-e1dd-457e-80df-247ff5b2587a','be57c417-1c49-437d-94f7-d1ca87982d8e',209,'text','- **Bản chất:** Bệnh nhân chỉ chia sẻ khi họ đã cảm nhận rõ rệt kết quả an toàn sinh học và sự dễ chịu trên cơ thể mình. Mọi lời mời đưa ra khi khách chưa hoàn tất chặng điều trị cốt lõi đều bị bộ não của họ phân loại vào dạng "mồi chài".- **Giải pháp Referral OS:** Nhân sự chỉ được bật công tắc mở lời khi hệ thống CRM chuyển trạng thái hồ sơ khách hàng sang nhãn `Satisfied` sau các mốc hậu kiểm thành công.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cda7f2b8-748d-41a7-ac76-2c1a15a1d2f6','28-referral-os','03db1af4-b812-4e7f-afdb-f13b42cd4559',4,'Sai lầm 3: Đánh đổi định vị cao cấp bằng tiền mặt (Cash-Driven Trap)','sai-lam-3-anh-oi-inh-vi-cao-cap-bang-tien-mat-cash-driven-trap',55,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1c9e44d6-8170-4ae4-b04c-9b5cf8d348da','cda7f2b8-748d-41a7-ac76-2c1a15a1d2f6',210,'text','- **Bản chất:** Nha khoa là ngành kinh doanh dựa trên mỏ neo niềm tin y khoa sâu sắc. Nếu bạn biến lời giới thiệu thành một giao dịch thương mại thuần túy bằng tiền mặt, bạn đang ngầm định bảo với khách hàng rằng chất lượng của bạn không đủ tốt nên phải dùng tiền để mua chuộc.- **Giải pháp Referral OS:** Chuyển dịch toàn bộ cơ chế thưởng sang dạng **Đặc quyền chăm sóc sức khỏe danh giá** (VIP Club, Gói bảo trì nướu chuyên sâu, Thẻ nụ cười gia đình) để giữ vẹn nguyên tính nhân văn của thương hiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5e1d2596-ee47-4b2a-8da9-cdfff2463d9a','28-referral-os','03db1af4-b812-4e7f-afdb-f13b42cd4559',4,'Sai lầm 4: Bỏ trống hạ tầng bảo vệ uy tín người giới thiệu (Referee Neglect)','sai-lam-4-bo-trong-ha-tang-bao-ve-uy-tin-nguoi-gioi-thieu-referee-neglect',56,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('48f53f22-192b-443d-9d66-43d2adb9adeb','5e1d2596-ee47-4b2a-8da9-cdfff2463d9a',211,'text','- **Bản chất:** Người cũ giới thiệu người mới tức là họ đang đem danh dự của mình ra để bảo chứng cho phòng khám. Nếu người mới gặp phải trải nghiệm tồi, người cũ sẽ là người đầu tiên cảm thấy bị tổn thương và hối hận.- **Giải pháp Referral OS:** Áp dụng nghiêm ngặt quy trình **Chăm sóc kép (Dual-Care)** tại Mục 22.9. Đánh dấu nhãn VIP cho toàn bộ nhóm Referral Lead ngay khi check-in tại sảnh Hà Nội.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('09795590-da9b-49d1-a3dc-19cb9caa4ece','28-referral-os','03db1af4-b812-4e7f-afdb-f13b42cd4559',4,'Sai lầm 5: Đóng màn che dữ liệu vận hành (Data Blindness)','sai-lam-5-ong-man-che-du-lieu-van-hanh-data-blindness',57,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6e7686f0-dc51-465c-abb3-362e0f1864db','09795590-da9b-49d1-a3dc-19cb9caa4ece',212,'text','- **Bản chất:** Vận hành hệ thống tăng trưởng hữu cơ mà không đo lường được chỉ số lan truyền (K\\text{-factor}) hay tỷ lệ đóng góp doanh thu của tệp cũ là bạn đang ném tiền qua cửa sổ mà không biết chương trình nào thực sự mang lại hiệu quả kinh tế.- **Giải pháp Referral OS:** Khóa chết tính năng lưu hồ sơ trên CRM nếu Lễ tân bỏ trống trường dữ liệu `Referrer_ID`. Tổ chức đối soát kỹ thuật số định kỳ hằng tuần.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('678f93fe-d537-4c5d-a1db-87c377eb873e','28-referral-os','03db1af4-b812-4e7f-afdb-f13b42cd4559',4,'Sai lầm 6: Sự im lặng vô ơn của hệ thống (Gratitude Amnesia)','sai-lam-6-su-im-lang-vo-on-cua-he-thong-gratitude-amnesia',58,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4a46a6cb-7219-455b-b42f-aacf055aa2b0','678f93fe-d537-4c5d-a1db-87c377eb873e',213,'text','- **Bản chất:** Khách hàng cũ không đòi hỏi phần thưởng của bạn, nhưng họ cần một lời ghi nhận chân thành. Sự thờ ơ, im lặng của phòng khám sau khi thu được tiền từ người mới sẽ khiến khách cũ cảm thấy mình bị lợi dụng.- **Giải pháp Referral OS:** Thiết lập lệnh tự động (Automation Workflow): Ngay khi hóa đơn của khách mới được duyệt thành công \\rightarrow Hệ thống tự động bắn một cuộc gọi tri ân từ CSKH và gửi quà cảm ơn cá nhân hóa đến Zalo của khách cũ trong vòng 2 giờ làm việc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6aa40b26-de70-487f-b8f3-2fdb1f0d1ed9','678f93fe-d537-4c5d-a1db-87c377eb873e',214,'text','**Mantra điều hành chống lỗi hệ thống:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('286abc89-5836-46a3-a8b4-6219c21ca073','678f93fe-d537-4c5d-a1db-87c377eb873e',215,'text','*"Sáu sai lầm trên chính là những sát thủ thầm lặng giết chết lòng tin của bệnh nhân. Hãy nhớ rằng, xây dựng Referral OS là xây dựng một mối quan hệ dài hạn dựa trên sự tử tế và tính sòng phẳng. Một lỗi sai nhỏ ở khâu đối xử hay quên ơn sẽ phá hủy toàn bộ công sức xây dựng móng nền chuyên môn của Bác sĩ Vinh."*',NULL,NULL,NULL,NULL,NULL);
