INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1470f2d6-db43-4975-aa6a-04fbb7736ab6','28-referral-os',NULL,2,'28.10 Nhịp Vận Hành Trách Nhiệm Dashboard Định Kỳ (Operational Routine Rhythm)','2810-nhip-van-hanh-trach-nhiem-dashboard-inh-ky-operational-routine-rhythm',60,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c6e07339-2293-4e4b-ac60-d9f1879b1a00','1470f2d6-db43-4975-aa6a-04fbb7736ab6',217,'text','Để hệ thống Dashboard của **Referral OS** không biến thành các con số tĩnh trên màn hình, phòng khám thiết lập kỷ luật vận hành nghiêm ngặt thông qua 3 nhịp kiểm toán: Hằng ngày (Thực thi), Hằng tuần (Đánh giá chặng ngắn) và Hằng tháng (Đánh giá dài hạn).',NULL,NULL,NULL,NULL,NULL);
