INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ca47160d-1c83-44ac-946e-085c930c693e','7c31f0be-e6cd-42c5-a423-a867962832ee',220,'text','Trọng tâm của nhịp tuần là phát hiện các nút thắt cổ chai trong đường ống chuyển đổi và giải quyết triệt để quyền lợi khách hàng:',NULL,NULL,NULL,NULL,NULL);
