INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('df02e36e-47e0-4e16-9f13-c1f50a0519a4','972018ed-2567-49bb-bbfb-99d213d1cc71',222,'text','Trọng tâm của nhịp tháng là đánh giá tính kinh tế của các chương trình chiến dịch và ra quyết định tối ưu hóa dòng tiền ròng:',NULL,NULL,NULL,NULL,NULL);
