INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d6f35b79-1a02-4a0b-8775-18b839613b82','972018ed-2567-49bb-bbfb-99d213d1cc71',224,'text','**Mantra điều hành nhịp trách nhiệm:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('333dfaf9-6918-4382-9708-f1099d6a0467','972018ed-2567-49bb-bbfb-99d213d1cc71',225,'text','*"Nhịp vận hành Dashboard chính là nhịp đập của bộ máy tăng trưởng hữu cơ. Sai sót một ngày sẽ làm hỏng dữ liệu một tuần; buông lỏng một tuần sẽ làm chệch hướng chiến lược của một tháng. Hãy biến việc cập nhật và đối soát các chỉ số này thành thói quen vô điều kiện của từng nhân sự tại nha khoa Thích Làm Răng."*',NULL,NULL,NULL,NULL,NULL);
