INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('16d89a1d-81f9-4ee8-b952-2da538aa4750','28-referral-os',NULL,2,'28.12. Kết Luận Toàn Chương','2812-ket-luan-toan-chuong',68,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7543b8c7-991d-44ac-8f21-0a1179fadf96','16d89a1d-81f9-4ee8-b952-2da538aa4750',226,'text','Hệ điều hành **Referral OS** không phải là một chiến dịch tiếp thị ngắn hạn hay một thủ thuật gia tăng doanh số nhất thời. Trong kiến trúc tổng thể của **Dental Empire OS**, đây là trục động cơ tối thượng chịu trách nhiệm chuyển hóa toàn bộ "thặng dư lòng tin" của bệnh nhân thành nguồn năng lượng tăng trưởng tự thân, bền vững và miễn nhiễm với các biến động chi phí quảng cáo ngoài thị trường.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('268665ff-0d00-4f45-ad39-8e48e3a3837c','28-referral-os','16d89a1d-81f9-4ee8-b952-2da538aa4750',3,'Hệ Tọa Độ Phối Hợp Của Các Hệ Điều Hành Trong Dental Empire','he-toa-o-phoi-hop-cua-cac-he-ieu-hanh-trong-dental-empire',69,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c9e66eab-6903-49ac-b26a-f5e73fb57209','268665ff-0d00-4f45-ad39-8e48e3a3837c',227,'text','Để nhìn rõ bức tranh vĩ mô, Ban quản trị nha khoa **Thích Làm Răng** cần thấu suốt vai trò mắt xích của Referral OS khi đặt cạnh các phân hệ vận hành khác:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('773bf787-6274-42a2-8d85-42100b6ff9ff','28-referral-os','16d89a1d-81f9-4ee8-b952-2da538aa4750',3,'Bản Chất Của Một Hệ Thống Referral Mạnh Mẽ','ban-chat-cua-mot-he-thong-referral-manh-me',70,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('273ff4bd-2c44-48ec-9851-4a16282654c2','773bf787-6274-42a2-8d85-42100b6ff9ff',228,'text','Một hệ thống Referral OS mạnh mẽ tuyệt đối không đến từ việc ép buộc nhân sự phải "gài bẫy" hay khéo léo "nài ép" bệnh nhân cho số điện thoại người quen. Sức mạnh nội tại của hệ thống đến từ việc thiết lập một quy trình vận hành đồng bộ từ lâm sàng đến dịch vụ, khiến người bệnh tự động nảy sinh ba nhận thức sâu sắc trong tâm trí:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9cfa30c7-de32-4958-81dc-88e6011a5f73','773bf787-6274-42a2-8d85-42100b6ff9ff',229,'text','- **Tôi tin tưởng tuyệt đối:** Lòng tin sắt đá vào năng lực chuyên môn y khoa của Bác sĩ Vinh và sự tử tế của thương hiệu.- **Tôi kiêu hãnh khi chia sẻ:** Cảm giác tự hào, định vị được nâng cao trước bạn bè, đồng nghiệp khi giới thiệu cho họ một địa chỉ chăm sóc răng miệng đẳng cấp, minh bạch tại Hà Nội.- **Tôi an tâm hoàn toàn:** Sự bảo chứng chắc chắn rằng người thân yêu của mình khi bước vào sàn sẽ được nâng niu, bảo vệ và chăm sóc bằng một tiêu chuẩn VIP không ma sát.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6c240ca1-e79a-47b0-9664-ea32d1c1f878','773bf787-6274-42a2-8d85-42100b6ff9ff',230,'text','Khi ba bộ lọc tâm lý này được lấp đầy, phòng khám sẽ chính thức bước qua giai đoạn tìm kiếm khách hàng nhỏ lẻ để tiến vào trạng thái sở hữu một **Cộng đồng người hộ vệ thương hiệu**. Họ không chỉ mang lại dòng doanh thu hữu cơ khổng lồ mà còn là những người bảo vệ, bảo chứng và lan tỏa giá trị cốt lõi của nha khoa Thích Làm Răng đi muôn nơi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('028657d7-87ab-4eee-8176-fcb0ab6e504e','773bf787-6274-42a2-8d85-42100b6ff9ff',231,'text','**MANTRA CỐT LÕI KHÓA CHƯƠNG REFFERAL OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('57d7ab70-9ef3-4488-93cd-c2200bdd8ed2','773bf787-6274-42a2-8d85-42100b6ff9ff',232,'text','*"Marketing trả phí có thể giúp chúng ta mua được lượt hiển thị, nhưng chỉ có sự tử tế trong y khoa và sự khoa học trong quy trình mới giúp chúng ta có được lời giới thiệu của người bệnh. Hãy vận hành Referral OS bằng cả cái đầu lạnh của dữ liệu CRM lẫn trái tim ấm của người làm ngành y, để biến mỗi nụ cười hạnh phúc của khách hàng cũ thành thỏi nam châm thu hút hàng ngàn nụ cười mới."*',NULL,NULL,NULL,NULL,NULL);
